```ts
import { setup, assign } from 'xstate';

interface CounterContext {
  readonly count: number;
  readonly lastDelta: number;
}

type CounterEvent =
  | { type: 'increment'; by: number }
  | { type: 'decrement'; by: number }
  | { type: 'reset' };

export const counterMachine = setup({
  types: {
    context: {} as CounterContext,
    events: {} as CounterEvent,
  },
}).createMachine({
  id: 'counter',
  initial: 'idle',
  context: { count: 0, lastDelta: 0 },
  states: {
    idle: {
      on: {
        increment: {
          actions: assign({
            count: ({ context, event }) => context.count + event.by,
            lastDelta: ({ event }) => event.by,
          }),
        },
        decrement: {
          actions: assign({
            count: ({ context, event }) => context.count - event.by,
            lastDelta: ({ event }) => -event.by,
          }),
        },
        reset: {
          actions: assign({ count: 0, lastDelta: 0 }),
        },
      },
    },
  },
});
