`emit` sends a typed side-channel event; consumers subscribe with `actor.on('TYPE', ...)`. Unlike `raise`, emitted events are never handled by the machine itself.

```ts
import { setup, emit } from 'xstate';

type Ev = { type: 'PING' };
type Emitted = { type: 'pong'; at: number };

export const pinger = setup({
  types: {
    events: {} as Ev,
    emitted: {} as Emitted,
  },
}).createMachine({
  id: 'pinger',
  on: {
    PING: {
      actions: emit(() => ({ type: 'pong', at: Date.now() })),
    },
  },
});

// const actor = createActor(pinger);
// actor.on('pong', (e) => console.log('pong at', e.at));
// actor.start();
// actor.send({ type: 'PING' });
```

