v5 introduced `emit` for this. Declare the emitted event type in `setup.types.emitted`, call `emit(...)` inside any action, and subscribe with `actor.on('type', handler)`.

```ts
import { setup, emit } from 'xstate';

type Ev = { type: 'SUBMIT'; form: string };
type Emitted = { type: 'submitted'; form: string };

export const form = setup({
  types: {
    events: {} as Ev,
    emitted: {} as Emitted,
  },
}).createMachine({
  id: 'form',
  on: {
    SUBMIT: {
      actions: emit(({ event }) => ({
        type: 'submitted',
        form: event.form,
      })),
    },
  },
});

// const actor = createActor(form);
// actor.on('submitted', ({ form }) => track('submit', form));
```

```ts
import { setup, assign, emit } from 'xstate';

interface OrderContext {
  orderId: string;
  totalCents: number;
}

type OrderEvent =
  | { type: 'ADD_ITEM'; priceCents: number }
  | { type: 'CHECKOUT' };

type OrderEmitted =
  | { type: 'itemAdded'; totalCents: number }
  | { type: 'checkedOut'; orderId: string; totalCents: number };

export const orderMachine = setup({
  types: {
    context: {} as OrderContext,
    events: {} as OrderEvent,
    emitted: {} as OrderEmitted,
  },
}).createMachine({
  id: 'order',
  context: { orderId: 'ord_1', totalCents: 0 },
  initial: 'open',
  states: {
    open: {
      on: {
        ADD_ITEM: {
          actions: [
            assign({
              totalCents: ({ context, event }) =>
                context.totalCents + event.priceCents,
            }),
            emit(({ context, event }) => ({
              type: 'itemAdded',
              totalCents: context.totalCents + event.priceCents,
            })),
          ],
        },
        CHECKOUT: {
          target: 'closed',
          actions: emit(({ context }) => ({
            type: 'checkedOut',
            orderId: context.orderId,
            totalCents: context.totalCents,
          })),
        },
      },
    },
    closed: { type: 'final' },
  },
});
```

