  id: 'audit',
  context: { userId: 'u_1', actions: 0 },
  on: {
    LOGIN: {
      actions: emit(({ context }) => ({
        type: 'audit',
        kind: 'login',
        userId: context.userId,
      })),
    },
    LOGOUT: {
      actions: emit(({ context }) => ({
        type: 'audit',
        kind: 'logout',
        userId: context.userId,
      })),
    },
    ACTION: {
      actions: [
        assign({ actions: ({ context }) => context.actions + 1 }),
        emit(({ context, event }) => ({
