```ts
import {
  setup,
  enqueueActions,
  assign,
  fromCallback,
  type ActorRefFrom,
} from 'xstate';

const workerLogic = fromCallback<{ type: 'RUN' } | { type: 'STOP' }>(
  ({ receive }) => {
    receive((event) => {
      if (event.type === 'RUN') console.log('running');
      if (event.type === 'STOP') console.log('stopping');
    });
  },
);

type SupervisorContext = {
  worker: ActorRefFrom<typeof workerLogic> | null;
  busy: boolean;
};

type SupervisorEvent = { type: 'TICK' } | { type: 'BOOT' };

export const supervisorMachine = setup({
  types: {
    context: {} as SupervisorContext,
    events: {} as SupervisorEvent,
  },
  actors: { workerLogic },
  guards: {
    hasWorker: ({ context }) => context.worker !== null,
    isBusy: ({ context }) => context.busy,
  },
}).createMachine({
  id: 'supervisor',
  context: { worker: null, busy: false },
  on: {
    BOOT: {
      actions: assign({
        worker: ({ spawn }) => spawn('workerLogic'),
      }),
    },
    TICK: {
      actions: enqueueActions(({ enqueue, check, context }) => {
        if (!check('hasWorker') || context.worker === null) return;
        if (check('isBusy')) {
          enqueue.sendTo(context.worker, { type: 'STOP' });
          enqueue.assign({ busy: false });
        } else {
          enqueue.sendTo(context.worker, { type: 'RUN' });
          enqueue.assign({ busy: true });
        }
      }),
    },
  },
});
```

