import { setup, fromCallback, assign, sendTo } from 'xstate';

type InEvent = { type: 'SEND'; text: string };
type OutEvent = { type: 'MESSAGE'; text: string };
type Events = OutEvent | InEvent;

const chatActor = fromCallback<InEvent, { endpoint: string }>(
  ({ input, sendBack, receive }) => {
    const ws = new WebSocket(input.endpoint);
    ws.addEventListener('message', (ev) => {
      sendBack({ type: 'MESSAGE', text: String(ev.data) });
    });
    receive((ev) => {
      if (ev.type === 'SEND' && ws.readyState === WebSocket.OPEN) {
