    tap: assign({ taps: ({ context }) => context.taps + 1 }),
  },
}).createMachine({
  id: 'counter',
  context: { restarts: 0, taps: 0 },
  initial: 'running',
  states: {
    running: {
      entry: 'onEnter',
      on: {
        RESTART: { target: 'running', reenter: true },
        INCR: { actions: 'tap' },
      },
    },
  },
});
