```ts
import { setup, fromPromise, assign } from 'xstate';

type Context = { n: number; attempts: number; error?: string };
type Events = { type: 'GO' } | { type: 'RETRY' };

const load = fromPromise<number, undefined>(async () => {
  const r = await fetch('/api/n');
  if (!r.ok) throw new Error('bad');
  return (await r.json()) as number;
});

export const m = setup({
  types: {
    context: {} as Context,
    events: {} as Events,
  },
  guards: {
    canRetry: ({ context }) => context.attempts < 4,
  },
  delays: {
    backoff: ({ context }) => 2 ** context.attempts * 250,
  },
  actors: { load },
}).createMachine({
  id: 'm',
  context: { n: 0, attempts: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        GO: {
          target: 'loading',
          actions: assign({ attempts: 0, error: undefined }),
        },
      },
    },
    loading: {
      invoke: {
        src: 'load',
        onDone: {
          target: 'ok',
          actions: assign({ n: ({ event }) => event.output }),
        },
        onError: [
          {
            guard: 'canRetry',
            target: 'waiting',
            actions: assign({
              attempts: ({ context }) => context.attempts + 1,
              error: ({ event }) =>
                event.error instanceof Error
                  ? event.error.message
                  : String(event.error),
            }),
          },
          {
            target: 'failed',
            actions: assign({
              error: ({ event }) =>
                event.error instanceof Error
                  ? event.error.message
                  : String(event.error),
            }),
          },
        ],
      },
    },
    waiting: {
      after: { backoff: 'loading' },
    },
    ok: { type: 'final' },
    failed: {
      on: { RETRY: { target: 'loading', actions: assign({ attempts: 0 }) } },
    },
  },
});
