  id: 'todo',
  context: { items: [] },
  on: {
    ADD:    { actions: assign({ items: (ctx, e) => [...ctx.items, e.text] }) },
    REMOVE: { actions: assign({ items: (ctx, e) => ctx.items.filter((_, i) => i !== e.index) }) },
