```ts
import { setup, fromTransition } from 'xstate';

type TodoEvent =
  | { type: 'ADD'; text: string }
  | { type: 'REMOVE'; index: number }
  | { type: 'CLEAR' };

interface TodoState {
  items: string[];
}

const todoLogic = fromTransition(
  (state: TodoState, event: TodoEvent): TodoState => {
    switch (event.type) {
      case 'ADD':
        return { items: [...state.items, event.text] };
      case 'REMOVE':
        return { items: state.items.filter((_, i) => i !== event.index) };
      case 'CLEAR':
        return { items: [] };
      default:
        return state;
    }
  },
  { items: [] }
);

export const todoParent = setup({
  types: {
    events: {} as TodoEvent,
  },
  actors: { todoLogic },
}).createMachine({
  id: 'todoParent',
  invoke: {
    id: 'todo',
    src: 'todoLogic',
  },
});
