    switch (event.type) {
      case 'SET':
        return { value: event.value };
      case 'CLEAR':
        return { value: '' };
      default:
        return state;
    }
  },
  { value: '' }
);

export const editorParent = setup({
  types: {
    events: {} as Ev,
  },
  actors: { draftLogic },
}).createMachine({
