import { setup, fromTransition } from 'xstate';

interface LogEntry {
  level: 'info' | 'warn' | 'error';
  message: string;
}

interface LogState {
  entries: LogEntry[];
}

type LogEvent =
  | { type: 'LOG'; entry: LogEntry }
  | { type: 'CLEAR' };

const MAX_ENTRIES = 5;
const initial: LogState = { entries: [] };

const logLogic = fromTransition(
  (state: LogState, event: LogEvent): LogState => {
    switch (event.type) {
      case 'LOG': {
        const next = [...state.entries, event.entry];
        return {
          entries:
            next.length > MAX_ENTRIES
              ? next.slice(next.length - MAX_ENTRIES)
              : next,
        };
      }
      case 'CLEAR':
        return { entries: [] };
      default:
        return state;
    }
  },
  initial
);

export const logParent = setup({
  types: {
    events: {} as LogEvent,
  },
  actors: { logLogic },
}).createMachine({
  id: 'logParent',
