  initial: 'closed',
  context: {},
  states: {
    closed: {
      on: { OPEN: { target: 'open.idle' } },
    },
    open: {
      initial: 'idle',
      on: { CANCEL: { target: 'closed' } },
      states: {
        idle: {
          on: { SUBMIT: { target: 'submitting' } },
        },
        submitting: {
          on: { CANCEL: { target: 'idle' } },
        },
      },
    },
  },
});
