          { guard: 'isInvalid', target: 'invalid' },
          { guard: 'isUnchanged', target: 'unchanged' },
          { target: 'saving' },
        ],
      },
    },
    invalid: { on: { SET_VALID: { target: 'idle', actions: 'setValid' } } },
    unchanged: { on: { SET_DIRTY: { target: 'idle', actions: 'setDirty' } } },
    saving: {
      on: { SAVED: { target: 'idle', actions: 'markClean' } },
