A `fromObservable<Event, Input>` actor wraps any subscribe-able stream into an XState actor. The factory receives `{ input }` and returns something with a `subscribe(observer)` method that returns an `unsubscribe` handle. Each value the observable pushes is treated as an event the parent can handle in its `on:` transitions. When the parent stops invoking the actor, XState calls `unsubscribe` for cleanup.

```ts
import {
  setup,
  assign,
  fromObservable,
  type Subscribable,
} from 'xstate';

type Quote = { type: 'QUOTE'; symbol: string; price: number };
type QuoteInput = { symbol: string; periodMs: number };

const quoteActor = fromObservable<Quote, QuoteInput>(({ input }) => {
  const stream: Subscribable<Quote> = {
    subscribe(observer) {
      const id = setInterval(() => {
        const ev: Quote = {
          type: 'QUOTE',
          symbol: input.symbol,
          price: Math.random() * 100,
        };
        if (typeof observer === 'function') observer(ev);
        else observer.next?.(ev);
      }, input.periodMs);
      return { unsubscribe: () => clearInterval(id) };
    },
  };
  return stream;
});

export const tickerMachine = setup({
  types: {
    context: {} as { last: number | null },
    events: {} as Quote,
  },
  actors: { quoteActor },
}).createMachine({
  id: 'ticker',
  context: { last: null },
  initial: 'watching',
  states: {
    watching: {
      invoke: {
        src: 'quoteActor',
        input: { symbol: 'AAPL', periodMs: 1000 },
      },
      on: {
        QUOTE: {
          actions: assign({ last: ({ event }) => event.price }),
        },
      },
    },
  },
});
