In XState v5 you spawn a child dynamically from inside an `assign` using the `spawn` helper supplied to the assigner callback: `assign({ ref: ({ spawn }) => spawn('child', { id: 'c' }) })`. The child must be declared in `setup.actors` so it can be referenced by string, and the ref's type is derived with `ActorRefFrom<typeof child>`. You tear the child down with `stopChild(id)` (or automatically on machine stop).

```ts
import {
  setup,
  assign,
  stopChild,
  type ActorRefFrom,
} from 'xstate';

const pingPong = setup({
  types: {
    context: {} as { pings: number },
    events: {} as { type: 'PING' },
  },
}).createMachine({
  id: 'pingPong',
  context: { pings: 0 },
  on: {
    PING: { actions: assign({ pings: ({ context }) => context.pings + 1 }) },
  },
});

type PPRef = ActorRefFrom<typeof pingPong>;

export const host = setup({
  types: {
    context: {} as { child: PPRef | null },
    events: {} as { type: 'START' } | { type: 'END' },
  },
  actors: { pingPong },
}).createMachine({
  id: 'host',
  context: { child: null },
  initial: 'idle',
  states: {
    idle: {
      on: {
        START: {
          target: 'running',
          actions: assign({
            child: ({ spawn }) => spawn('pingPong', { id: 'pp' }),
          }),
        },
      },
    },
    running: {
      on: {
        END: {
          target: 'idle',
          actions: [stopChild('pp'), assign({ child: null })],
        },
      },
    },
  },
});
