  setup,
  assign,
  sendTo,
  sendParent,
  type ActorRefFrom,
} from 'xstate';

const pongActor = setup({
  types: {
    context: {} as {},
    events: {} as { type: 'PING'; n: number },
  },
}).createMachine({
  id: 'pong',
  on: {
    PING: {
      actions: sendParent(({ event }) => ({
        type: 'PONG' as const,
        n: event.n,
      })),
    },
  },
});

type PongRef = ActorRefFrom<typeof pongActor>;

export const pingMachine = setup({
  types: {
    context: {} as { pong: PongRef | null; count: number },
    events: {} as
      | { type: 'INIT' }
      | { type: 'PING' }
      | { type: 'PONG'; n: number },
  },
  actors: { pongActor },
}).createMachine({
  id: 'ping',
  context: { pong: null, count: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        INIT: {
          target: 'active',
          actions: assign({
            pong: ({ spawn }) => spawn('pongActor', { id: 'pong' }),
          }),
        },
      },
    },
    active: {
      on: {
        PING: {
