Use a transient `debouncing` state with an `after` block. Each incoming event re-enters `debouncing`, which restarts the timer; the timer firing is the commit.

```ts
import { setup, assign } from 'xstate';

type Context = { query: string; committed: string };
type Event = { type: 'INPUT'; value: string };

export const debounceMachine = setup({
  types: {
    context: {} as Context,
    events: {} as Event,
  },
}).createMachine({
  id: 'debounce',
  initial: 'idle',
  context: { query: '', committed: '' },
  states: {
    idle: {
      on: {
        INPUT: {
          target: 'debouncing',
          actions: assign({ query: ({ event }) => event.value }),
        },
      },
    },
    debouncing: {
      on: {
        INPUT: {
          target: 'debouncing',
          reenter: true,
          actions: assign({ query: ({ event }) => event.value }),
        },
      },
      after: {
        500: {
          target: 'idle',
          actions: assign({ committed: ({ context }) => context.query }),
        },
      },
    },
  },
});
```

