```ts
import { setup, assign } from 'xstate';

type AuctionContext = {
  windowMs: number;
  highBid: number;
  winner: string | null;
};

type AuctionEvent =
  | { type: 'BID'; amount: number; bidder: string }
  | { type: 'EXTEND'; ms: number };

export const auctionMachine = setup({
  types: {
    context: {} as AuctionContext,
    events: {} as AuctionEvent,
  },
  actions: {
    acceptBid: assign({
      highBid: ({ event }) =>
        event.type === 'BID' ? event.amount : 0,
      winner: ({ event }) =>
        event.type === 'BID' ? event.bidder : null,
    }),
    extendWindow: assign({
      windowMs: ({ context, event }) =>
        event.type === 'EXTEND' ? context.windowMs + event.ms : context.windowMs,
    }),
  },
  delays: {
    closeWindow: ({ context }) => context.windowMs,
  },
}).createMachine({
  id: 'auction',
  initial: 'open',
  context: { windowMs: 30000, highBid: 0, winner: null },
  states: {
    open: {
      after: {
        closeWindow: { target: 'closed' },
      },
      on: {
        BID: {
          target: 'open',
          reenter: true,
          actions: 'acceptBid',
        },
        EXTEND: { actions: 'extendWindow' },
      },
    },
    closed: { type: 'final' },
  },
});
```

In v5 an `after` block attaches delayed transitions to a state. Keys can be either a literal millisecond number or a name referring to `setup.delays`. The timer starts when the state is entered and is cancelled when the state is exited (whether by another event or by the timer itself firing). Named delays can read `context` so each instance can time itself individually.

```ts
import { setup, assign } from 'xstate';

type ToastContext = { visibleFor: number };
type ToastEvent = { type: 'SHOW' } | { type: 'DISMISS' };

export const toastMachine = setup({
  types: {
    context: {} as ToastContext,
    events: {} as ToastEvent,
  },
  delays: {
    autoHide: ({ context }) => context.visibleFor,
  },
}).createMachine({
  id: 'toast',
  initial: 'hidden',
  context: { visibleFor: 4000 },
  states: {
    hidden: {
      on: { SHOW: { target: 'visible' } },
    },
    visible: {
      after: {
        autoHide: { target: 'hidden' },
      },
      on: {
        DISMISS: { target: 'hidden' },
      },
    },
  },
});
```

Add a 10-second idle timeout to this v5 machine so that `editing` moves to `saved` if nothing happens:

```ts
import { setup, assign } from 'xstate';

type Ctx = { draft: string };
type Ev = { type: 'EDIT'; value: string } | { type: 'SAVE' };

export const editor = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'editor',
  initial: 'editing',
  context: { draft: '' },
  states: {
    editing: {
      on: {
        EDIT: { actions: assign({ draft: ({ event }) => event.value }) },
        SAVE: { target: 'saved' },
      },
    },
    saved: {},
  },
});
```

