import { setup, assign } from 'xstate';

type Ctx = { tallies: Record<string, number> };

type Ev =
  | { type: 'VOTE'; candidate: string }
  | { type: 'CLOSE' };

type Out = { winner: string; votes: number };

export const voteMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    output: {} as Out,
  },
}).createMachine({
  id: 'vote',
  initial: 'open',
  context: { tallies: {} },
  states: {
    open: {
      on: {
        VOTE: {
          actions: assign({
            tallies: ({ context, event }) => ({
              ...context.tallies,
              [event.candidate]: (context.tallies[event.candidate] ?? 0) + 1,
            }),
          }),
        },
        CLOSE: 'closed',
      },
    },
    closed: { type: 'final' },
  },
  output: ({ context }) => {
    let winner = '';
    let votes = 0;
    for (const [name, n] of Object.entries(context.tallies)) {
      if (n > votes) {
        votes = n;
        winner = name;
      }
    }
    return { winner, votes };
  },
});
