      on: {
        DO: 'working',
        STOP: 'cancelled',
      },
    },
    working: {
      on: { STOP: 'cancelled' },
      after: { 1000: 'done' },
    },
    done: {
      entry: sendTo(({ self }) => self._parent!, { type: 'CHILD_DONE' }),
      type: 'final',
    },
    cancelled: {
      entry: sendTo(({ self }) => self._parent!, { type: 'CHILD_CANCELLED' }),
      type: 'final',
    },
  },
