A rate-limited counter tracks a bucket of remaining tokens. Each HIT debits a token; when tokens reach zero the machine moves to a throttled state and refuses further hits until refilled. Here is a minimal typed implementation:

```ts
import { setup, assign } from 'xstate';

type Ctx = { tokens: number; capacity: number };
type Ev =
  | { type: 'HIT' }
  | { type: 'REFILL' };

export const rateLimited = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
  guards: {
    hasTokens: ({ context }) => context.tokens > 0,
  },
}).createMachine({
  id: 'rateLimited',
  initial: 'open',
  context: { tokens: 5, capacity: 5 },
  states: {
    open: {
      on: {
        HIT: [
          {
            guard: 'hasTokens',
            actions: assign({ tokens: ({ context }) => context.tokens - 1 }),
          },
          { target: 'throttled' },
        ],
        REFILL: {
          actions: assign({ tokens: ({ context }) => context.capacity }),
        },
      },
    },
    throttled: {
      on: {
        REFILL: {
          target: 'open',
          actions: assign({ tokens: ({ context }) => context.capacity }),
        },
      },
    },
  },
});
```

