```ts
import { Effect, Data } from "effect";

interface User { readonly id: string; readonly name: string }
interface Order { readonly id: string; readonly total: number }

class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}
class OrdersUnavailable extends Data.TaggedError("OrdersUnavailable")<{ readonly userId: string }> {}

declare const fetchUser: (id: string) => Effect.Effect<User, UserNotFound>;
declare const fetchOrders: (userId: string) => Effect.Effect<ReadonlyArray<Order>, OrdersUnavailable>;

export const loadUserWithOrders = (
  id: string
): Effect.Effect<{ user: User; orders: ReadonlyArray<Order> }, UserNotFound | OrdersUnavailable> =>
  Effect.gen(function* () {
    const user = yield* fetchUser(id);
    const orders = yield* fetchOrders(user.id);
    return { user, orders };
  });
```

`Effect.gen` threads the typed error channel across both yields — the result type is `Effect<..., UserNotFound | OrdersUnavailable>`, so neither error can be accidentally swallowed.

```ts
import { Effect } from "effect";

declare const readConfig: () => Effect.Effect<{ baseUrl: string }>;
declare const authenticate: (baseUrl: string) => Effect.Effect<string>;
declare const fetchProfile: (baseUrl: string, token: string) => Effect.Effect<{ name: string }>;

export const greeting: Effect.Effect<string> = Effect.gen(function* () {
  const cfg = yield* readConfig();
  const token = yield* authenticate(cfg.baseUrl);
  const profile = yield* fetchProfile(cfg.baseUrl, token);
  return `hello ${profile.name}`;
});
```

Each `yield*` unwraps one effect and binds the success value; the error + requirement channels accumulate automatically.

```ts
import { Effect } from "effect";

declare const loadA: Effect.Effect<number>;
declare const loadB: (n: number) => Effect.Effect<string>;

// v3: no adapter arg — yield* directly on the Effect.
export const program: Effect.Effect<string> = Effect.gen(function* () {
  const a = yield* loadA;
  const b = yield* loadB(a);
  return b;
});
```

In v3 the generator takes zero arguments and `yield*` consumes an `Effect` directly; the `_` adapter form from v2 is gone.

```ts
import { Effect } from "effect";

interface User { readonly id: string }
interface Order { readonly id: string }

declare const getUser: () => Effect.Effect<User>;
declare const getOrders: (userId: string) => Effect.Effect<ReadonlyArray<Order>>;

export const program: Effect.Effect<ReadonlyArray<Order>> = Effect.gen(function* () {
  const u = yield* getUser();
  const o = yield* getOrders(u.id);
  return o;
});
```

Drop the `$` adapter parameter; `yield*` now accepts an `Effect` directly in v3.

`Effect.gen(function* () { ... })` takes a zero-arg generator and runs it as a sequential effect. Each `yield* someEffect` suspends until the effect completes, then binds the success value. Errors and requirements propagate into the outer `Effect<A, E, R>` type automatically, so the compiler tracks the full channel without you naming types at every step.

```ts
import { Effect, Data } from "effect";

interface Row { readonly id: string; readonly payload: string }

class DbError extends Data.TaggedError("DbError")<{ readonly cause: string }> {}
class PublishError extends Data.TaggedError("PublishError")<{ readonly topic: string }> {}

declare const readRow: (id: string) => Effect.Effect<Row, DbError>;
declare const publish: (topic: string, body: string) => Effect.Effect<void, PublishError>;

export const forward = (
  id: string,
  topic: string
): Effect.Effect<void, DbError | PublishError> =>
  Effect.gen(function* () {
    const row = yield* readRow(id);
    yield* publish(topic, row.payload);
  });
```

```ts
import { Effect, Data } from "effect";

interface Item { readonly sku: string; readonly priceCents: number; readonly qty: number }

class EmptyCart extends Data.TaggedError("EmptyCart")<{ readonly reason: string }> {}
class InvalidItem extends Data.TaggedError("InvalidItem")<{ readonly sku: string }> {}

const validateItem = (it: Item): Effect.Effect<Item, InvalidItem> =>
  it.qty > 0 && it.priceCents >= 0
    ? Effect.succeed(it)
    : Effect.fail(new InvalidItem({ sku: it.sku }));

export const totalCents = (
  items: ReadonlyArray<Item>
): Effect.Effect<number, EmptyCart | InvalidItem> =>
  Effect.gen(function* () {
    if (items.length === 0) return yield* Effect.fail(new EmptyCart({ reason: "no items" }));
    let sum = 0;
    for (const it of items) {
      const ok = yield* validateItem(it);
      sum += ok.priceCents * ok.qty;
    }
    return sum;
  });
```

The error channel is `EmptyCart | InvalidItem`, a typed union the caller can discriminate on `_tag`.

```ts
import { Effect } from "effect";

declare const readA: Effect.Effect<number>;
declare const readB: (a: number) => Effect.Effect<string>;
declare const readC: (b: string) => Effect.Effect<boolean>;

export const program: Effect.Effect<boolean> = Effect.gen(function* () {
  const a = yield* readA;
  const b = yield* readB(a);
  const c = yield* readC(b);
  return c;
});
```

With three sequential dependent effects, `Effect.gen` reads top-to-bottom and keeps every intermediate value in scope — far clearer than a nested `flatMap` chain.

```ts
import { Effect, Data } from "effect";

interface Quote { readonly symbol: string; readonly price: number }

class PrimaryDown extends Data.TaggedError("PrimaryDown")<{ readonly reason: string }> {}
class FallbackDown extends Data.TaggedError("FallbackDown")<{ readonly reason: string }> {}

declare const primary: (sym: string) => Effect.Effect<Quote, PrimaryDown>;
declare const fallback: (sym: string) => Effect.Effect<Quote, FallbackDown>;

export const getQuote = (sym: string): Effect.Effect<Quote, FallbackDown> =>
  Effect.gen(function* () {
    const first = yield* Effect.either(primary(sym));
    if (first._tag === "Right") return first.right;
    const second = yield* fallback(sym);
    return second;
  });
```

`Effect.either` lifts the primary's failure into a value so the generator can branch without letting `PrimaryDown` leak into the result type.

```ts
import { Effect, Option, Data } from "effect";

interface User { readonly id: string; readonly name: string }

class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}

declare const cacheGet: (id: string) => Effect.Effect<Option.Option<User>>;
declare const fetchUser: (id: string) => Effect.Effect<User, UserNotFound>;
declare const cachePut: (u: User) => Effect.Effect<void>;

export const getUser = (id: string): Effect.Effect<User, UserNotFound> =>
  Effect.gen(function* () {
    const cached = yield* cacheGet(id);
    if (Option.isSome(cached)) return cached.value;
    const u = yield* fetchUser(id);
    yield* cachePut(u);
    return u;
  });
```

The cache path returns inside the generator without calling `fetchUser`, so the miss-path remains the only place the `UserNotFound` error can surface.

```ts
