```ts
import { Effect, Data } from "effect";

interface Cart { readonly id: string; readonly totalCents: number }
interface Reservation { readonly reservationId: string }
interface Charge { readonly chargeId: string }
interface Receipt { readonly receiptId: string }

class InventoryError extends Data.TaggedError("InventoryError")<{ readonly cartId: string }> {}
class PaymentError extends Data.TaggedError("PaymentError")<{ readonly chargeAttempt: string }> {}
class ReceiptError extends Data.TaggedError("ReceiptError")<{ readonly cartId: string }> {}

declare const reserve: (c: Cart) => Effect.Effect<Reservation, InventoryError>;
declare const charge: (c: Cart, r: Reservation) => Effect.Effect<Charge, PaymentError>;
declare const emit: (c: Cart, ch: Charge) => Effect.Effect<Receipt, ReceiptError>;

export const checkout = (
  cart: Cart
): Effect.Effect<Receipt, InventoryError | PaymentError | ReceiptError> =>
