`while (true)` inside `Effect.gen` is safe — each iteration's `yield* Effect.sleep(...)` suspends the fiber, so nothing is busy-looping.

```ts
import { Effect, Data } from "effect";

interface Header { readonly count: number }

class HeaderError extends Data.TaggedError("HeaderError")<{ readonly raw: string }> {}
class BodyError extends Data.TaggedError("BodyError")<{ readonly index: number }> {}

declare const readLine: () => Effect.Effect<string>;

const parseHeader = (raw: string): Effect.Effect<Header, HeaderError> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0
    ? Effect.succeed({ count: n })
    : Effect.fail(new HeaderError({ raw }));
};

export const parseMessage = (): Effect.Effect<
  { header: Header; body: ReadonlyArray<string> },
  HeaderError | BodyError
> =>
  Effect.gen(function* () {
    const headerRaw = yield* readLine();
    const header = yield* parseHeader(headerRaw);
    const body: string[] = [];
    for (let i = 0; i < header.count; i++) {
      const line = yield* readLine();
      if (line.length === 0) return yield* Effect.fail(new BodyError({ index: i }));
      body.push(line);
    }
    return { header, body };
  });
```

```ts
import { Effect, Context, Layer } from "effect";

// --- Logger ---
interface Logger { readonly info: (msg: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger");

const LoggerLive = Layer.succeed(Logger, {
  info: (msg) => Effect.sync(() => console.log(`[info] ${msg}`)),
});

// --- TodoStore (needs Logger) ---
interface Todo { readonly id: string; readonly title: string }
interface TodoStore { readonly list: () => Effect.Effect<ReadonlyArray<Todo>> }
const TodoStore = Context.GenericTag<TodoStore>("app/TodoStore");

const TodoStoreLive = Layer.effect(
  TodoStore,
  Effect.gen(function* () {
    const log = yield* Logger;
    return {
      list: () =>
        Effect.gen(function* () {
          yield* log.info("todo:list");
          return [] as ReadonlyArray<Todo>;
        }),
    };
  })
);

// --- Wire: TodoStore depends on Logger, so LoggerLive must be provided first. ---
const AppLayer = Layer.provide(TodoStoreLive, LoggerLive);
const FullLayer = Layer.merge(LoggerLive, AppLayer);

const program = Effect.gen(function* () {
  const store = yield* TodoStore;
  const todos = yield* store.list();
  return todos.length;
});

export const runnable = Effect.provide(program, FullLayer);
```

`Layer.provide(TodoStoreLive, LoggerLive)` satisfies TodoStore's Logger dependency; merging with `LoggerLive` keeps Logger exposed to the program too.

```ts
import { Effect, Context, Layer } from "effect";

interface Clock { readonly now: () => Effect.Effect<number> }
const Clock = Context.GenericTag<Clock>("app/Clock");

interface Random { readonly next: () => Effect.Effect<number> }
const Random = Context.GenericTag<Random>("app/Random");

const ClockLive = Layer.succeed(Clock, { now: () => Effect.succeed(Date.now()) });
const RandomLive = Layer.effect(Random, Effect.succeed({ next: () => Effect.succeed(Math.random()) }));

// Both are leaf services — merge to expose both to one program.
const BaseLayer = Layer.merge(ClockLive, RandomLive);

const program = Effect.gen(function* () {
  const c = yield* Clock;
  const r = yield* Random;
  const t = yield* c.now();
  const x = yield* r.next();
  return { t, x };
});

export const runnable = Effect.provide(program, BaseLayer);
```

`Layer.merge` combines independent layers; use `Layer.provide` when one layer needs the other as input.

```ts
import { Effect, Context, Layer } from "effect";

interface Config { readonly host: string }
interface Metrics { readonly inc: (key: string) => Effect.Effect<void> }

const Config = Context.GenericTag<Config>("app/Config");
const Metrics = Context.GenericTag<Metrics>("app/Metrics");

const ConfigLive = Layer.succeed(Config, { host: "localhost" });
const MetricsLive = Layer.effect(
  Metrics,
  Effect.succeed({ inc: (_: string) => Effect.void })
);

// Merge then provide once.
const AppLayer = Layer.merge(ConfigLive, MetricsLive);

const program = Effect.gen(function* () {
  const cfg = yield* Config;
  const m = yield* Metrics;
  yield* m.inc("start");
  return cfg.host;
});

export const runnable = Effect.provide(program, AppLayer);
```

One `Effect.provide` at the edge consumes both services in `R`; the inner program stays pure and polymorphic over layer choice.

```ts
import { Effect, Context, Layer } from "effect";

interface Inner { readonly kind: "inner" }
interface Outer { readonly kind: "outer" }

const Inner = Context.GenericTag<Inner>("app/Inner");
const Outer = Context.GenericTag<Outer>("app/Outer");

const InnerLive = Layer.succeed(Inner, { kind: "inner" });
const OuterLive = Layer.succeed(Outer, { kind: "outer" });

// v3: Layer.provide takes (inner, deps) positionally.
const WiredOuter = Layer.provide(OuterLive, InnerLive);

const program = Effect.gen(function* () {
  const o = yield* Outer;
  return o.kind;
});

// v3: Effect.provide, not Effect.provideLayer.
export const runnable = Effect.provide(program, WiredOuter);
```

Both `Layer.provide` and `Effect.provide` take their arguments positionally in v3; the `provideLayer` name is gone.

A `Layer<ROut, E, RIn>` describes how to produce `ROut` given `RIn`. Leaves use `Layer.succeed` (pure) or `Layer.effect` (effectful construction). You compose with `Layer.merge` (union the outputs) and `Layer.provide(inner, deps)` (satisfy `inner`'s `RIn` from `deps`'s `ROut`). The final `Effect.provide(program, AppLayer)` closes the `R` channel entirely.

```ts
import { Effect, Context, Layer } from "effect";

interface Config { readonly dsn: string }
const Config = Context.GenericTag<Config>("app/Config");

interface Db { readonly ping: () => Effect.Effect<boolean> }
const Db = Context.GenericTag<Db>("app/Db");

interface Cache { readonly size: () => Effect.Effect<number> }
const Cache = Context.GenericTag<Cache>("app/Cache");

const ConfigLive = Layer.succeed(Config, { dsn: "postgres://localhost/app" });

const DbLive = Layer.effect(
  Db,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return { ping: () => Effect.succeed(cfg.dsn.length > 0) };
  })
);

const CacheLive = Layer.effect(
  Cache,
  Effect.gen(function* () {
    yield* Config; // reserved for future use
    return { size: () => Effect.succeed(0) };
  })
);

// Db and Cache both need Config. Merge the two dependents, then provide Config once.
const AppLayer = Layer.provide(Layer.merge(DbLive, CacheLive), ConfigLive);

const program = Effect.gen(function* () {
  const db = yield* Db;
  const c = yield* Cache;
  const ok = yield* db.ping();
  const n = yield* c.size();
  return { ok, n };
});

export const runnable = Effect.provide(program, AppLayer);
```

