```ts
import { Effect, Context, Layer } from "effect";

interface A { readonly tag: "A" }
interface B { readonly tag: "B" }
interface C { readonly tag: "C" }
interface D { readonly tag: "D" }

const A = Context.GenericTag<A>("app/A");
const B = Context.GenericTag<B>("app/B");
const C = Context.GenericTag<C>("app/C");
const D = Context.GenericTag<D>("app/D");

const ALive = Layer.succeed(A, { tag: "A" });
const BLive = Layer.succeed(B, { tag: "B" });
const CLive = Layer.effect(C, Effect.succeed({ tag: "C" as const }));
const DLive = Layer.effect(D, Effect.succeed({ tag: "D" as const }));

// Flat variadic form.
export const AppLayer = Layer.mergeAll(ALive, BLive, CLive, DLive);
```

`Layer.mergeAll(...layers)` avoids the nested `merge(merge(...))` tree — easier to read and still type-checks the union of outputs.

`Layer.effect(Tag, builderEffect)` produces a service by running `builderEffect` once when the layer is provided. The builder is an `Effect<Service, E, R>` — its `R` channel names which upstream services it needs. Yield those services inside `Effect.gen`, close over them in the service's method closures, and return the final `Service` record. The builder runs lazily on first use and is memoised per layer.

