import { Effect, Context, Layer } from "effect";

interface Config { readonly host: string }
interface Service { readonly describe: () => Effect.Effect<string> }

const Config = Context.GenericTag<Config>("app/Config");
const Service = Context.GenericTag<Service>("app/Service");

const ConfigLive = Layer.succeed(Config, { host: "localhost" });
const ServiceLive = Layer.effect(
  Service,
  Effect.gen(function* () {
    const cfg = yield* Config;
    return { describe: () => Effect.succeed(`svc@${cfg.host}`) };
  })
);

// Layer.provide hides Config. Layer.provideMerge keeps it exposed.
const AppLayer = Layer.provideMerge(ServiceLive, ConfigLive);

const program = Effect.gen(function* () {
  const svc = yield* Service;
  const cfg = yield* Config; // still available
  const name = yield* svc.describe();
  return `${name} (${cfg.host})`;
});

export const runnable = Effect.provide(program, AppLayer);
