import { Effect, Data } from "effect";

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

const fetchBody = (url: string): Effect.Effect<string, NetworkError> =>
  Effect.tryPromise({
    try: () => fetch(url).then((r) => r.text()),
    catch: (cause) => new NetworkError({ cause }),
  });

const parseInt10 = (s: string): Effect.Effect<number, ParseError> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n)
    ? Effect.fail(new ParseError({ raw: s }))
    : Effect.succeed(n);
};

export const program: Effect.Effect<number, ParseError> = Effect.gen(function* () {
  const body = yield* fetchBody("/count");
  return yield* parseInt10(body);
}).pipe(Effect.catchTag("NetworkError", () => Effect.succeed("0").pipe(Effect.flatMap(parseInt10))));
```

`Effect.catchTag` takes the `_tag` **string** (not the class reference). Once `NetworkError` is caught, only `ParseError` remains in the error channel.

```typescript
import { Effect, Data } from "effect";

class DbError extends Data.TaggedError("DbError")<{ readonly cause: unknown }> {}

const query = (sql: string): Effect.Effect<readonly unknown[], DbError> =>
  Effect.tryPromise({
    try: async () => {
      if (!sql) throw new Error("empty sql");
      return [] as readonly unknown[];
    },
    catch: (cause) => new DbError({ cause }),
  });

export const program: Effect.Effect<number, never> = query("select 1").pipe(
  Effect.map((rows) => rows.length),
  Effect.catchTag("DbError", (e) => Effect.sync(() => {
    console.error("db fail", e.cause);
    return 0;
  }))
);
```

v3 prefers tagged-error classes over raw `Error` — `Effect.catchTag("DbError", ...)` can then discriminate on `_tag` and narrow `e` to `DbError` with a typed `cause` field.

```typescript
import { Effect, Data } from "effect";

class NotFoundError extends Data.TaggedError("NotFoundError")<{ readonly id: string }> {}
class DbError extends Data.TaggedError("DbError")<{ readonly cause: unknown }> {}

const find = (id: string): Effect.Effect<string, NotFoundError | DbError> =>
  id === "" ? Effect.fail(new NotFoundError({ id })) : Effect.succeed("row");

export const program: Effect.Effect<string | null, DbError> = find("").pipe(
  Effect.catchTag("NotFoundError", () => Effect.succeed(null))
);
```

String-matching on `.message` is fragile — tagging errors with `Data.TaggedError` gives `Effect.catchTag` a real discriminator and removes the caught case from the error channel.

```typescript
import { Effect, Data, Schedule, Duration } from "effect";

interface User { readonly id: string; readonly name: string }

class NetworkError extends Data.TaggedError("NetworkError")<{ readonly cause: unknown }> {}
class NotFoundError extends Data.TaggedError("NotFoundError")<{ readonly id: string }> {}

declare const fetchUserRaw: (id: string) => Effect.Effect<User, NetworkError | NotFoundError>;

const backoff = Schedule.exponential(Duration.millis(100)).pipe(Schedule.compose(Schedule.recurs(3)));

export const fetchUser = (id: string): Effect.Effect<User, NotFoundError> =>
  fetchUserRaw(id).pipe(
    Effect.retry({ schedule: backoff, while: (e) => e._tag === "NetworkError" }),
    Effect.catchTag("NetworkError", (e) => Effect.die(e))
  );
```

The `while` guard on `Effect.retry` uses `_tag` to retry only on `NetworkError`; after the bounded schedule is exhausted, the remaining `NetworkError` is promoted to a defect with `Effect.die`, leaving `NotFoundError` in the error channel.

```typescript
