class AuthError extends Data.TaggedError("AuthError")<{ readonly reason: string }> {}
class RateLimited extends Data.TaggedError("RateLimited")<{ readonly retryAfter: number }> {}

const op: Effect.Effect<string, AuthError | RateLimited> = Effect.fail(
  new RateLimited({ retryAfter: 3 })
);

export const handled: Effect.Effect<string, AuthError> = op.pipe(
  Effect.catchTag("RateLimited", (e) => Effect.succeed(`retry in ${e.retryAfter}s`))
);
