class FooErr extends Data.TaggedError("FooErr")<{ readonly msg: string }> {}
class BarErr extends Data.TaggedError("BarErr")<{ readonly code: number }> {}

const op = (x: number): Effect.Effect<number, FooErr | BarErr> =>
  x < 0
    ? Effect.fail(new FooErr({ msg: "negative" }))
    : x > 100
      ? Effect.fail(new BarErr({ code: x }))
      : Effect.succeed(x);

export const handled: Effect.Effect<number, BarErr> = op(-1).pipe(
  Effect.catchTag("FooErr", () => Effect.succeed(0))
);
```

`Data.TaggedError` gives you structural equality, a stable `_tag`, and auto-generated constructors — same shape as the hand-rolled class, one import instead of boilerplate.

`Effect.catchTag(tagString, handler)` removes the matched tag from the error channel if the handler returns a success, or replaces it with the handler's own error type if the handler re-fails. The discriminator is the string `_tag`, not the class itself, so this works for both `Data.TaggedError` and hand-rolled `{ readonly _tag: "..." }` shapes.

```typescript
