The resulting `E` is `Forbidden` only — `NotFound` is gone because the handler's success drained it.

```typescript
import { Effect, Data } from "effect";

class FileMissing extends Data.TaggedError("FileMissing")<{ readonly path: string }> {}
class ParseError extends Data.TaggedError("ParseError")<{ readonly raw: string }> {}

interface Config { readonly apiUrl: string }

const read = (path: string): Effect.Effect<string, FileMissing> =>
  path.endsWith(".json")
    ? Effect.succeed('{"apiUrl":"x"}')
    : Effect.fail(new FileMissing({ path }));

const parse = (raw: string): Effect.Effect<Config, ParseError> =>
  Effect.try({
    try: () => JSON.parse(raw) as Config,
    catch: () => new ParseError({ raw }),
  });

export const load = (path: string): Effect.Effect<Config, ParseError> =>
  Effect.gen(function* () {
    const raw = yield* read(path);
    return yield* parse(raw);
  }).pipe(
    Effect.catchTag("FileMissing", () => Effect.succeed({ apiUrl: "default" }))
  );
```

`FileMissing` is swallowed into a default value; `ParseError` stays in the channel because the caller probably wants to see malformed configs.

```typescript
import { Effect, Data } from "effect";

class CardDeclined extends Data.TaggedError("CardDeclined")<{ readonly reason: string }> {}
class GatewayDown extends Data.TaggedError("GatewayDown")<{ readonly cause: unknown }> {}
class Fraud extends Data.TaggedError("Fraud")<{ readonly score: number }> {}

const charge = (amount: number): Effect.Effect<string, CardDeclined | GatewayDown | Fraud> => {
  if (amount <= 0) return Effect.fail(new CardDeclined({ reason: "bad amount" }));
  if (amount > 10_000) return Effect.fail(new Fraud({ score: 99 }));
  return Effect.succeed("ch_123");
};

export const handled: Effect.Effect<string, Fraud> = charge(50).pipe(
  Effect.catchTag("CardDeclined", (e) => Effect.succeed(`declined:${e.reason}`)),
  Effect.catchTag("GatewayDown", (_e) => Effect.succeed("retry-later"))
);
