```typescript
import { Effect, Data } from "effect";

class MalformedToken extends Data.TaggedError("MalformedToken")<{ readonly raw: string }> {}
class ExpiredToken extends Data.TaggedError("ExpiredToken")<{ readonly exp: number }> {}

interface Claims { readonly sub: string; readonly exp: number }

const parse = (raw: string): Effect.Effect<Claims, MalformedToken> =>
  raw.split(".").length === 3
    ? Effect.succeed({ sub: "user", exp: Date.now() / 1000 - 1 })
    : Effect.fail(new MalformedToken({ raw }));

const checkExp = (c: Claims): Effect.Effect<Claims, ExpiredToken> =>
  c.exp > Date.now() / 1000
    ? Effect.succeed(c)
    : Effect.fail(new ExpiredToken({ exp: c.exp }));

export const decode = (raw: string): Effect.Effect<Claims | null, MalformedToken> =>
  parse(raw).pipe(
    Effect.flatMap(checkExp),
    Effect.catchTag("ExpiredToken", () => Effect.succeed(null))
  );
```

`ExpiredToken` becomes a `null` claims result (caller decides to re-auth); `MalformedToken` stays typed in the channel because a bad input shape is probably a bug.

