```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

interface Address { city?: string }
interface User { address?: Address }

export const getCity = (user: User | null | undefined): string =>
  pipe(
    O.fromNullable(user),
    O.chain((u) => O.fromNullable(u.address)),
    O.chain((a) => O.fromNullable(a.city)),
    O.map((c) => c.toUpperCase()),
    O.getOrElse<string>(() => 'UNKNOWN'),
  );
```

`O.fromNullable` lifts each `T | undefined` into `Option<T>`, `O.chain` keeps us in the `Option` world when the next step also returns an `Option`, and `O.getOrElse` collapses the pipeline to a plain `string` at the end.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

interface User { email?: string | null }

export const firstEmail = (users: ReadonlyArray<User>): string =>
  pipe(
    O.fromNullable(users[0]),
    O.chain((u) => O.fromNullable(u.email)),
    O.map((e) => e.toLowerCase()),
    O.getOrElse<string>(() => 'none'),
  );
```

The nested ternary becomes a linear pipeline. `O.fromNullable` handles both `undefined` (empty array) and `null` (missing email) uniformly.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const scores = new Map<string, number>([['alice', 91], ['bob', 73]]);

export const scoreFor = (name: string): number =>
  pipe(
    O.fromNullable(scores.get(name)),
    O.map((n) => Math.round(n)),
    O.getOrElse<number>(() => 0),
  );
```

`Map.get` returns `V | undefined`, which `O.fromNullable` lifts straight into `Option<V>` without any explicit `if` branch.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const parseInt10 = (s: string): O.Option<number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n) ? O.none : O.some(n);
};

const nonZero = (n: number): O.Option<number> =>
  n === 0 ? O.none : O.some(n);

export const reciprocalOf = (input: string): number =>
  pipe(
    parseInt10(input),
    O.chain(nonZero),
    O.map((n) => 1 / n),
    O.getOrElse<number>(() => -1),
  );
```

Both `parseInt10` and `nonZero` return `Option<number>`, so each composes with `O.chain`. The final `O.map` stays on successful values only.

`O.chain` is bind/flatMap for `Option`: if the input is `Some`, it runs your function (which itself returns an `Option`) and keeps the result; if the input is `None`, it short-circuits. `O.map` is the same idea but for plain value-returning functions.

```ts
