```

Each refinement step returns `Option<number>`, so `O.chain` threads them while preserving the short-circuit on any failure.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const notEmpty = (s: string): O.Option<string> =>
  s.length > 0 ? O.some(s) : O.none;

export const resolveId = (id: string | null | undefined): string =>
  pipe(
    O.fromNullable(id),
    O.map((x) => x.trim()),
    O.chain(notEmpty),
    O.getOrElse<string>(() => {
      console.warn('[resolveId] falling back to guest');
      return 'guest';
    }),
  );
```

The logging lives inside the `getOrElse` thunk — it only fires on the `None` branch, and the pipeline's return type stays `string`.

```ts
