Swap `O.map` for `O.chain` whenever the step function itself returns an `Option`. `O.map` is for plain `A -> B`; `O.chain` flattens `A -> Option<B>` to avoid the nested wrapper.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const head = <A>(xs: ReadonlyArray<A>): O.Option<A> =>
  xs.length > 0 ? O.some(xs[0]) : O.none;

export const firstOr = <A, B>(
  xs: ReadonlyArray<A>,
  f: (a: A) => B,
  fallback: B,
): B =>
  pipe(
    head(xs),
    O.map(f),
    O.getOrElse<B>(() => fallback),
  );

export const firstName = (names: ReadonlyArray<string>): string =>
  firstOr(names, (s) => s.toUpperCase(), 'NONE');
```

The generic `head` keeps the domain logic honest — we cannot accidentally read `xs[0]` on an empty array since the type says `Option<A>`, not `A`.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

const parseJson = (s: string): O.Option<unknown> => {
  try {
    return O.some(JSON.parse(s) as unknown);
  } catch {
    return O.none;
  }
};

const asRecord = (u: unknown): O.Option<Record<string, unknown>> =>
  typeof u === 'object' && u !== null ? O.some(u as Record<string, unknown>) : O.none;

const asString = (u: unknown): O.Option<string> =>
  typeof u === 'string' ? O.some(u) : O.none;

export const versionOf = (raw: string): string =>
  pipe(
    parseJson(raw),
    O.chain(asRecord),
    O.chain((r) => O.fromNullable(r.version)),
    O.chain(asString),
    O.getOrElse<string>(() => '0.0.0'),
  );
