import * as O from 'fp-ts/Option';

export const trimmed = (input: string | null | undefined): string =>
  pipe(
    O.fromNullable(input),
    O.map((s) => s.trim()),
    O.getOrElse<string>(() => 'x'),
  );
```

Data-first with `pipe` reads top-to-bottom in the same order the data flows. The nested form reads inside-out, which is why it feels awkward with three or more steps.

```ts
