export const flag = (flags: Flags, name: string): boolean =>
  pipe(
    O.fromNullable(flags[name]),
    O.chain(asBool),
    O.getOrElse<boolean>(() => false),
  );
```

Both "missing key" and "wrong type" collapse to `None`, so the fallback path is singular.

```ts
