```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

const nonEmpty = (s: string): E.Either<string, string> =>
  s.trim().length > 0 ? E.right(s) : E.left('email is required');

const hasAt = (s: string): E.Either<string, string> =>
  s.includes('@') ? E.right(s) : E.left("email must contain '@'");

const underMaxLen = (s: string): E.Either<string, string> =>
  s.length < 254 ? E.right(s) : E.left('email must be < 254 chars');

export const validateEmail = (s: string): E.Either<string, string> =>
  pipe(
    nonEmpty(s),
    E.chainW(hasAt),
    E.chainW(underMaxLen),
    E.mapLeft((msg) => `[email] ${msg}`),
  );
```

`E.chainW` is the widening variant — here all the error types happen to be `string`, but using `chainW` keeps the door open to different left types without a manual unification.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type NanErr = { readonly _tag: 'NanErr' };
type NegErr = { readonly _tag: 'NegErr' };

const parseNumber = (s: string): E.Either<NanErr, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left({ _tag: 'NanErr' }) : E.right(n);
};

const nonNegative = (n: number): E.Either<NegErr, number> =>
  n >= 0 ? E.right(n) : E.left({ _tag: 'NegErr' });

export const parse = (s: string): E.Either<NanErr | NegErr, number> =>
  pipe(parseNumber(s), E.chainW(nonNegative));
```

Replacing `throw` with tagged `Left` values makes both failure modes show up in the return type, so the caller cannot forget either.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseError = { kind: 'parse'; raw: string };
type RangeError = { kind: 'range'; value: number };

const parseIntStrict = (s: string): E.Either<ParseError, number> => {
  const n = Number.parseInt(s, 10);
  return Number.isNaN(n) ? E.left({ kind: 'parse', raw: s }) : E.right(n);
};

const inRange = (n: number): E.Either<RangeError, number> =>
  n >= 0 && n <= 100 ? E.right(n) : E.left({ kind: 'range', value: n });

export const parsePercent = (
  s: string,
): E.Either<ParseError | RangeError, number> =>
  pipe(parseIntStrict(s), E.chainW(inRange));
```

`E.chainW` widens the left channel to the union of both error types. Plain `E.chain` would require both sides to share an error type.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

class TooShort { readonly _tag = 'TooShort' as const }
class TooLong { readonly _tag = 'TooLong' as const }
class BadChars { readonly _tag = 'BadChars' as const }

const lengthOk = (s: string): E.Either<TooShort | TooLong, string> => {
  if (s.length < 3) return E.left(new TooShort());
  if (s.length > 20) return E.left(new TooLong());
  return E.right(s);
};

const alnumOnly = (s: string): E.Either<BadChars, string> =>
  /^[a-zA-Z0-9]+$/.test(s) ? E.right(s) : E.left(new BadChars());

export const normaliseUser = (raw: string): string =>
  pipe(
    lengthOk(raw),
    E.chainW(alnumOnly),
    E.map((s) => s.toLowerCase()),
    E.fold(
      (e) => `invalid:${e._tag}`,
      (u) => `ok:${u}`,
    ),
  );
```

`E.chain` / `E.chainW` is bind for `Either`: on `Right(a)` it runs your function `a -> Either<E', B>` and returns its result; on `Left(e)` it short-circuits. `E.chainW` is the widening form that lets each step have its own error type and unions them in the result.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseErr = 'parse';
type DivZero = 'divzero';

const num = (s: string): E.Either<ParseErr, number> => {
  const n = Number(s);
  return Number.isNaN(n) ? E.left('parse') : E.right(n);
};

const safeDiv = (a: number, b: number): E.Either<DivZero, number> =>
  b === 0 ? E.left('divzero') : E.right(a / b);

export const divide = (
  a: string,
  b: string,
): E.Either<ParseErr | DivZero, number> =>
  pipe(
    num(a),
    E.chainW((x) => pipe(num(b), E.chainW((y) => safeDiv(x, y)))),
  );
```

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

interface Raw { name?: unknown; age?: unknown }
interface Person { name: string; age: number }

const decode = (u: unknown): E.Either<{ code: 'decode' }, Raw> =>
  typeof u === 'object' && u !== null
    ? E.right(u as Raw)
    : E.left({ code: 'decode' });

const validate = (r: Raw): E.Either<{ code: 'validate'; field: string }, Person> => {
  if (typeof r.name !== 'string') return E.left({ code: 'validate', field: 'name' });
  if (typeof r.age !== 'number') return E.left({ code: 'validate', field: 'age' });
  return E.right({ name: r.name, age: r.age });
};

const persist = (p: Person): E.Either<{ code: 'persist' }, Person> =>
  p.age >= 0 ? E.right(p) : E.left({ code: 'persist' });

export const save = (input: unknown): E.Either<string, Person> =>
  pipe(
    decode(input),
    E.chainW(validate),
    E.chainW(persist),
    E.mapLeft((e) => `failed:${e.code}`),
  );
```

`E.chainW` lets each step keep its own tagged error; `E.mapLeft` collapses the union to a single string at the edge.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type Malformed = { kind: 'malformed'; part: string };

const splitPair = (part: string): E.Either<Malformed, readonly [string, string]> => {
  const i = part.indexOf('=');
  if (i <= 0) return E.left({ kind: 'malformed', part });
  return E.right([part.slice(0, i), part.slice(i + 1)] as const);
};

const reducePairs = (
  parts: ReadonlyArray<string>,
): E.Either<Malformed, Record<string, string>> =>
  parts.reduce<E.Either<Malformed, Record<string, string>>>(
    (acc, part) =>
      pipe(
        acc,
        E.chain((accMap) =>
          pipe(
            splitPair(part),
            E.map(([k, v]) => ({ ...accMap, [k]: v })),
          ),
        ),
      ),
    E.right({}),
  );

export const parseConfig = (raw: string): E.Either<Malformed, Record<string, string>> =>
  pipe(
    raw.split(';').filter((x) => x.length > 0),
    reducePairs,
  );
```

