import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type Shape = { _tag: 'Shape' };
type B64 = { _tag: 'B64' };
type Json = { _tag: 'Json' };

const splitThree = (raw: string): E.Either<Shape, [string, string, string]> => {
  const parts = raw.split('.');
  return parts.length === 3 ? E.right([parts[0], parts[1], parts[2]]) : E.left({ _tag: 'Shape' });
};

const decodeB64 = (s: string): E.Either<B64, string> => {
  try {
    return E.right(Buffer.from(s, 'base64url').toString('utf8'));
  } catch {
    return E.left({ _tag: 'B64' });
  }
};

const parseJson = (s: string): E.Either<Json, unknown> => {
  try {
    return E.right(JSON.parse(s) as unknown);
  } catch {
    return E.left({ _tag: 'Json' });
  }
};

export const decodePayload = (token: string): E.Either<Shape | B64 | Json, unknown> =>
  pipe(
    splitThree(token),
    E.chainW(([, body]) => decodeB64(body)),
    E.chainW(parseJson),
  );
