`E.match` is `E.fold` by another name — both collapse `Either<E, A>` to a single `B` by handling both sides.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseErr = { _tag: 'ParseErr'; raw: string };
type NegErr = { _tag: 'NegErr'; value: number };

const parsePositive = (s: string): E.Either<ParseErr | NegErr, number> => {
  const n = Number.parseInt(s, 10);
  if (Number.isNaN(n)) return E.left({ _tag: 'ParseErr', raw: s });
  if (n <= 0) return E.left({ _tag: 'NegErr', value: n });
  return E.right(n);
};

const scaled = (factor: number) =>
  (n: number): E.Either<never, number> => E.right(n * factor);

export const statusFor = (raw: string, factor: number): number =>
  pipe(
    parsePositive(raw),
    E.chainW(scaled(factor)),
    E.mapLeft((e) => e._tag === 'ParseErr' ? 400 : 422),
    E.fold(
      (code) => code,
      () => 200,
    ),
  );
```

```ts
