import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export interface FetchError {
  readonly _tag: 'FetchError';
  readonly message: string;
  readonly cause: unknown;
}

const toFetchError = (u: unknown): FetchError => ({
  _tag: 'FetchError',
  message: u instanceof Error ? u.message : String(u),
  cause: u,
});

export const fetchJson = <A>(url: string): TE.TaskEither<FetchError, A> =>
  TE.tryCatch(
    async () => {
      const res = await fetch(url);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return (await res.json()) as A;
    },
    toFetchError
  );

export const count = (url: string): TE.TaskEither<FetchError, number> =>
  pipe(
    fetchJson<ReadonlyArray<unknown>>(url),
    TE.map((xs) => xs.length)
  );
