`TE.tryCatch(() => Promise<A>, (u) => E)` runs the thunk, catches any throw, and routes it through the error narrower — the result is a `TaskEither<E, A>` that never throws, and `pipe` composes it further.

```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export class DbError {
  readonly _tag = 'DbError' as const;
  constructor(readonly op: string, readonly cause: unknown) {}
}

declare const pool: { query: (sql: string) => Promise<ReadonlyArray<unknown>> };

export const runQuery = (sql: string): TE.TaskEither<DbError, ReadonlyArray<unknown>> =>
  TE.tryCatch(
    () => pool.query(sql),
    (u) => new DbError(sql, u)
  );

