```ts
import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type RaceError =
  | { readonly _tag: 'TimeoutError'; readonly ms: number }
  | { readonly _tag: 'UpstreamError'; readonly cause: unknown };

const TIMEOUT_SENTINEL = Symbol('timeout');

export const withTimeout = <A>(ms: number, task: () => Promise<A>): TE.TaskEither<RaceError, A> =>
  TE.tryCatch(
    () =>
      Promise.race([
        task(),
        new Promise<never>((_, reject) => setTimeout(() => reject(TIMEOUT_SENTINEL), ms)),
      ]),
    (u): RaceError =>
      u === TIMEOUT_SENTINEL
        ? { _tag: 'TimeoutError', ms }
        : { _tag: 'UpstreamError', cause: u }
  );

