import { pipe } from 'fp-ts/function';
import * as TE from 'fp-ts/TaskEither';

export type IdbError =
  | { readonly _tag: 'BlockedError'; readonly name: string }
  | { readonly _tag: 'OpenFailed'; readonly cause: unknown };

