    O.chain((t) => O.fromNullable(t.colour)),
    O.getOrElse(() => 'default')
  );
```

Each `O.chain` step reads like a null-guarded field access — compare this to three nested ternaries, which scale catastrophically once you hit five levels of optionality.

```ts
import { pipe } from 'fp-ts/function';

interface UrlParts {
  readonly protocol: string;
  readonly host: string;
  readonly path: string;
  readonly query: string;
  readonly fragment: string;
}

const withProtocol = (p: string) => (u: UrlParts): UrlParts => ({ ...u, protocol: p });
const withHost = (h: string) => (u: UrlParts): UrlParts => ({ ...u, host: h });
const withPath = (p: string) => (u: UrlParts): UrlParts => ({ ...u, path: p });
const withQuery = (q: string) => (u: UrlParts): UrlParts => ({ ...u, query: q });
const withFragment = (f: string) => (u: UrlParts): UrlParts => ({ ...u, fragment: f });

const render = (u: UrlParts): string =>
  `${u.protocol}://${u.host}${u.path}${u.query ? `?${u.query}` : ''}${u.fragment ? `#${u.fragment}` : ''}`;

const empty: UrlParts = { protocol: '', host: '', path: '', query: '', fragment: '' };

export const buildUrl = (): string =>
  pipe(
    empty,
    withProtocol('https'),
    withHost('example.com'),
    withPath('/api/v1'),
    withQuery('id=42'),
    withFragment('top'),
    render
  );
```

Each `withX` is a point-free function from `UrlParts` to `UrlParts` — `pipe` then reads like a fluent builder without needing a class.

```ts
import { pipe } from 'fp-ts/function';
import * as A from 'fp-ts/ReadonlyArray';

interface Event { readonly type: string; readonly at: number }

const groupByType = (xs: ReadonlyArray<Event>): ReadonlyMap<string, number> => {
  const m = new Map<string, number>();
  for (const e of xs) m.set(e.type, (m.get(e.type) ?? 0) + 1);
  return m;
};

const toPairs = (m: ReadonlyMap<string, number>): ReadonlyArray<readonly [string, number]> =>
  Array.from(m.entries());

const format = A.map(([t, n]: readonly [string, number]) => `${t}:${n}`);

export const summarise = (events: ReadonlyArray<Event>): ReadonlyArray<string> =>
  pipe(events, groupByType, toPairs, format);
```

The outer `pipe` is one readable sentence — each step has a single responsibility and the final shape is obvious from the chain alone.

`pipe(x, f, g, h)` is the smallest possible primitive that expresses sequential data-first composition. Every other fp-ts combinator — `map`, `chain`, `filter`, `ap` — is designed to slot into a pipe, because pipe-friendly APIs compose trivially without naming intermediate values. That consistency is why fp-ts calls `pipe` canonical.

```ts
