const stripTags = (s: string): string => s.replace(/<[^>]*>/g, '');
const squashSpace = (s: string): string => s.replace(/\s+/g, ' ');
const trim = (s: string): string => s.trim();

export const sanitise = (raw: string): string =>
  pipe(raw, stripTags, squashSpace, trim);
```

Refactor this intermediate-variable-heavy function into fp-ts v2 `pipe`:
```ts
function calculate(input: string): number {
  const parsed = parseFloat(input);
  const halved = parsed / 2;
  const rounded = Math.round(halved);
  const clamped = Math.min(rounded, 100);
  return clamped;
}
```

```ts
import { pipe } from 'fp-ts/function';

const parse = (s: string): number => parseFloat(s);
const half = (n: number): number => n / 2;
const round = (n: number): number => Math.round(n);
const cap = (max: number) => (n: number): number => Math.min(n, max);

export const calculate = (input: string): number =>
  pipe(input, parse, half, round, cap(100));
```

Each `const x = f(prev)` line in the original was a name that only existed so you could type it on the next line. `pipe` removes the bookkeeping and keeps the transformation visible.

```ts
import { pipe } from 'fp-ts/function';

const square = (n: number): number => n * n;
const negate = (n: number): number => -n;
const add = (k: number) => (n: number): number => n + k;

export const run = (x: number): number => pipe(x, square, negate, add(1));

// Property: run(3) === -9 + 1 === -8
export const sanityCheck: number = run(3);
```

The numeric pipeline and its point-free form are interchangeable — the type system stays precise because each step has a simple `number -> number` signature.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ValidationError = { readonly _tag: 'ValidationError'; readonly field: string };
const err = (field: string): ValidationError => ({ _tag: 'ValidationError', field });

const nonEmpty = (s: string): E.Either<ValidationError, string> =>
  s.length > 0 ? E.right(s) : E.left(err('empty'));

const maxLen = (n: number) => (s: string): E.Either<ValidationError, string> =>
  s.length <= n ? E.right(s) : E.left(err(`>${n}`));

const noDigits = (s: string): E.Either<ValidationError, string> =>
  /\d/.test(s) ? E.left(err('digits')) : E.right(s);

export const validateName = (input: string): E.Either<ValidationError, string> =>
  pipe(input, nonEmpty, E.chain(maxLen(64)), E.chain(noDigits));
```

The first check kicks off the Either context; each subsequent `E.chain` receives the previous right value and either widens or short-circuits — the pipeline reads like a checklist.

```ts
import { pipe } from 'fp-ts/function';

const applyTax = (rate: number) => (n: number): number => n * (1 + rate);
const roundToCents = (n: number): number => Math.round(n * 100) / 100;
const toFixed2 = (n: number): string => n.toFixed(2);
const withSymbol = (sym: string) => (s: string): string => `${sym}${s}`;

export const format = (preTax: number): string =>
  pipe(preTax, applyTax(0.08), roundToCents, toFixed2, withSymbol('$'));

export const example: string = format(19.99);
```

The pipeline's order matches the accountant's order of operations — a reader can audit the business logic by reading down the call list once.

```ts
import { pipe } from 'fp-ts/function';
import * as O from 'fp-ts/Option';

interface Row { readonly values: ReadonlyArray<number> }
interface Sheet { readonly rows: ReadonlyArray<Row> }

const firstRow = (s: Sheet): O.Option<Row> =>
  s.rows.length > 0 ? O.some(s.rows[0]) : O.none;
const firstValue = (r: Row): O.Option<number> =>
  r.values.length > 0 ? O.some(r.values[0]) : O.none;

export const topLeft = (s: Sheet): number =>
  pipe(
    firstRow(s),
    O.chain(firstValue),
    O.getOrElse(() => 0)
  );
```

`O.chain` threads the lookup through each optional step, and `O.getOrElse` collapses to a concrete default at the end — the composition stays inside `pipe` the whole way.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type HandlerError =
  | { readonly _tag: 'MissingHeader' }
  | { readonly _tag: 'BadHeader'; readonly reason: string };

interface Request { readonly headers: Readonly<Record<string, string | undefined>> }

const getHeader = (req: Request): E.Either<HandlerError, string> => {
  const h = req.headers['x-token'];
  return h === undefined ? E.left({ _tag: 'MissingHeader' }) : E.right(h);
};

const parseToken = (raw: string): E.Either<HandlerError, { sub: string }> => {
  const parts = raw.split('.');
  return parts.length === 2
    ? E.right({ sub: parts[0] })
    : E.left({ _tag: 'BadHeader', reason: 'format' });
};

const requireSub = (t: { sub: string }): E.Either<HandlerError, string> =>
  t.sub.length > 0 ? E.right(t.sub) : E.left({ _tag: 'BadHeader', reason: 'no-sub' });

export const handle = (req: Request): E.Either<HandlerError, string> =>
  pipe(getHeader(req), E.chain(parseToken), E.chain(requireSub));
```

Each stage returns an Either with the same error type, so `E.chain` stitches them into a single short-circuiting pipeline.

```ts
import { pipe } from 'fp-ts/function';
import * as E from 'fp-ts/Either';

type ParseError =
  | { readonly _tag: 'BadJson' }
  | { readonly _tag: 'BadShape'; readonly field: string };

interface Payload { readonly id: string; readonly count: number }

const parseJson = (raw: string): E.Either<ParseError, unknown> => {
  try { return E.right(JSON.parse(raw) as unknown); }
  catch { return E.left({ _tag: 'BadJson' }); }
};

const validate = (u: unknown): E.Either<ParseError, Payload> => {
  if (typeof u !== 'object' || u === null) return E.left({ _tag: 'BadShape', field: 'root' });
  const r = u as { id?: unknown; count?: unknown };
  if (typeof r.id !== 'string') return E.left({ _tag: 'BadShape', field: 'id' });
  if (typeof r.count !== 'number') return E.left({ _tag: 'BadShape', field: 'count' });
  return E.right({ id: r.id, count: r.count });
};

const normalise = (p: Payload): Payload => ({ ...p, id: p.id.trim() });

export const ingest = (raw: string): E.Either<ParseError, Payload> =>
  pipe(parseJson(raw), E.chain(validate), E.map(normalise));
```

The pipeline reads like a state diagram: parse -> validate -> normalise, with any left short-circuiting the rest. `pipe` is the glue that makes the diagram one expression.

```ts
import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type UserId = string & Brand.Brand<"UserId">;
export const UserId = Brand.nominal<UserId>();

interface User { readonly id: UserId; readonly name: string }

declare const lookupUserUnsafe: (id: UserId) => Effect.Effect<User, Error>;

export const loadUser = (raw: string): Effect.Effect<User, Error> =>
  pipe(UserId(raw), lookupUserUnsafe);

// Call site: loadUser(UserId("u_42")) compiles; loadUser("u_42") does NOT.
```

`Brand.nominal` is type-only — there is no runtime check. The call site must pass through the smart constructor so the structural string is promoted to the nominal `UserId` before reaching `lookupUserUnsafe`.

```ts
import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type Email = string & Brand.Brand<"Email">;

export const Email = Brand.refined<Email>(
  (s) => s.includes("@") && s.length <= 254,
  (s) => Brand.error(`Not a valid email: ${s}`),
);

export const parseEmail = (raw: string): Effect.Effect<Email, Brand.Brand.BrandErrors> =>
  pipe(Email.either(raw), (e) => e._tag === "Right" ? Effect.succeed(e.right) : Effect.fail(e.left));
