import { Effect, Option } from "effect";
import { pipe } from "effect";

class VErr { readonly _tag = "VErr" as const; constructor(readonly msg: string) {} }

declare const vA: Effect.Effect<string, VErr>;
declare const vB: Effect.Effect<number, VErr>;
declare const vC: Effect.Effect<boolean, VErr>;

// Before: Effect.all([vA, vB, vC]) short-circuits on first failure and runs sequentially.
// After: parallel + validate mode, so every validator runs AND every error survives.
