const writeAndCommit = Effect.scoped(
  Effect.gen(function* () {
    const tx = yield* transaction;
    yield* Console.log(`INSERT ... in ${tx.id}`);
    yield* Ref.set(tx.status, "committed");
    return "ok" as const;
  })
);

Effect.runPromise(writeAndCommit).then(console.log);
