const program: Effect.Effect<number, Expired> = Effect.gen(function* () {
  const fiber = yield* Effect.fork(doWork);
  return yield* Effect.race(Fiber.join(fiber), deadline(200));
});

Effect.runPromise(Effect.either(program)).then(console.log);
```

Joining in a race lets the parent bail out while still cleanly interrupting the fibre.

```ts
import { Effect, Fiber } from "effect";

const fetchUser = Effect.succeed({ id: "u1", name: "Ada" });
const fetchOrders = Effect.succeed([{ id: "o1" }, { id: "o2" }]);

const program = Effect.gen(function* () {
  const uF = yield* Effect.fork(fetchUser);
  const oF = yield* Effect.fork(fetchOrders);
  const user = yield* Fiber.join(uF);
  const orders = yield* Fiber.join(oF);
  return [user, orders] as const;
});

Effect.runPromise(program).then(([u, o]) => console.log(u.name, o.length));
```

For N effects, prefer `Effect.all(effects, { concurrency: "unbounded" })`; explicit fork + join is for hand-rolled supervision.

```ts
import { Effect, Data, Duration } from "effect";

class DnsFail extends Data.TaggedError("DnsFail")<{ readonly host: string }> {}
class TlsFail extends Data.TaggedError("TlsFail")<{ readonly cert: string }> {}

const dnsResolve = (host: string): Effect.Effect<string, DnsFail> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(50));
    return yield* Effect.fail(new DnsFail({ host }));
  });

const tlsHandshake: Effect.Effect<string, TlsFail> = Effect.gen(function* () {
  yield* Effect.sleep(Duration.millis(80));
  return "tls-ok";
});

// Union preserved: DnsFail | TlsFail in the error channel.
const program: Effect.Effect<string, DnsFail | TlsFail> = Effect.race(dnsResolve("x"), tlsHandshake);

Effect.runPromise(Effect.either(program)).then(console.log);
```

`Effect.race` takes the first completer — success or failure; both error types stay visible until you handle them.

```ts
import { Effect, Fiber } from "effect";

const work: Effect.Effect<number> = Effect.gen(function* () {
  yield* Effect.sleep("40 millis");
  return 100;
});

// Effect equivalent of: const p = new Promise(...); p.then(handle).
const program = Effect.gen(function* () {
  const fiber = yield* Effect.fork(work);
  const result = yield* Fiber.join(fiber);
  return result * 2;
});

Effect.runPromise(program).then((n) => console.log("doubled:", n));
```

Unlike a bare Promise, the returned `Fiber` can be interrupted at any time, freeing the resources it holds.

```ts
import { Effect, Fiber } from "effect";

const a: Effect.Effect<number> = Effect.gen(function* () {
  yield* Effect.sleep("20 millis");
  return 10;
});
const b: Effect.Effect<number> = Effect.gen(function* () {
  yield* Effect.sleep("30 millis");
  return 32;
});

const program = Effect.gen(function* () {
  const fa = yield* Effect.fork(a);
  const fb = yield* Effect.fork(b);
  const ra = yield* Fiber.join(fa);
  const rb = yield* Fiber.join(fb);
  return [ra, rb] as const;
});

Effect.runPromise(program).then(([x, y]) => console.log(x, y));
```

The fork/join form lets you keep references to the fibres (for later interrupt) where `Effect.all` doesn't.

```ts
import { Effect, Fiber, Console, Duration } from "effect";

const worker = (name: string, ms: number): Effect.Effect<string> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return `done:${name}`;
  }).pipe(Effect.onInterrupt(() => Console.log(`[interrupt] ${name}`)));

const program: Effect.Effect<string> = Effect.gen(function* () {
  const fa = yield* Effect.fork(worker("A", 30));
  const fb = yield* Effect.fork(worker("B", 90));
  // Manual race: whichever finishes first, interrupt the other.
  return yield* Effect.race(Fiber.join(fa), Fiber.join(fb));
});

Effect.runPromise(program).then((r) => console.log(r));
```

`Effect.onInterrupt` gives the loser a chance to log (or flush) before it is fully cancelled.

```ts
import { Effect, Data, Duration } from "effect";

class ProbeFail extends Data.TaggedError("ProbeFail")<{ readonly url: string }> {}

const probe = (url: string, ms: number, ok: boolean): Effect.Effect<string, ProbeFail> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return ok ? url : yield* Effect.fail(new ProbeFail({ url }));
  });

const program: Effect.Effect<string, ProbeFail> = Effect.raceAll([
  probe("https://a", 70, false),
  probe("https://b", 40, true),
  probe("https://c", 55, true),
  probe("https://d", 90, false),
]);

Effect.runPromise(Effect.either(program)).then(console.log);
```

`raceAll` resolves to the first *successful* completion; remaining probes are interrupted.

`Effect.fork` creates a child fibre supervised by the *current* fibre's scope — if the parent exits, the child is interrupted. `Effect.forkDaemon` forks against the global scope so the fibre outlives the parent.

```ts
import { Effect, Fiber, Console } from "effect";

const beat = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("tick");
    yield* Effect.sleep("40 millis");
  })
);

const program = Effect.gen(function* () {
  const hb = yield* Effect.fork(beat);
  yield* Effect.sleep("90 millis");
  yield* Fiber.interrupt(hb);
  yield* Console.log("parent done");
});

Effect.runPromise(program);
```

Because `hb` is a supervised fork, even if we forget to interrupt it, program exit cancels it automatically.

```ts
import { Effect, Data, Duration } from "effect";

class Boom extends Data.TaggedError("Boom")<{ readonly which: string }> {}

const ok = (ms: number): Effect.Effect<string, Boom> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return "ok";
  });

const bad = (ms: number, tag: string): Effect.Effect<string, Boom> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new Boom({ which: tag }));
  });

// Effect.all with unbounded concurrency short-circuits on first failure
// and interrupts the other fibres.
const program: Effect.Effect<readonly string[], Boom> = Effect.all(
  [ok(80), bad(40, "x"), ok(60)],
  { concurrency: "unbounded" }
);

Effect.runPromise(Effect.either(program)).then(console.log);
```

For first-error short-circuit across many effects prefer `Effect.all(..., { concurrency })`; use `raceAll` when you want the *first success* instead.

```ts
import { Effect, Duration } from "effect";

interface CacheHit { readonly _tag: "cache"; readonly value: string }
interface NetHit { readonly _tag: "net"; readonly value: string; readonly ms: number }
type Hit = CacheHit | NetHit;

const cacheHit: Effect.Effect<Hit> = Effect.gen(function* () {
  yield* Effect.sleep(Duration.millis(25));
  return { _tag: "cache", value: "cached" } as const;
});

const netHit: Effect.Effect<Hit> = Effect.gen(function* () {
  yield* Effect.sleep(Duration.millis(80));
  return { _tag: "net", value: "fresh", ms: 80 } as const;
});

const program: Effect.Effect<Hit> = Effect.race(cacheHit, netHit);

Effect.runPromise(program).then((h) => {
  if (h._tag === "cache") console.log("hit cache:", h.value);
  else console.log(`fresh in ${h.ms}ms: ${h.value}`);
});
```

By funnelling both branches through a shared `Hit` union, consumer code stays exhaustive.

```ts
import { Effect, Fiber, Console } from "effect";

const poller = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("[poll] tick");
    yield* Effect.sleep("30 millis");
  })
);

const condition: Effect.Effect<"stop"> = Effect.gen(function* () {
  yield* Effect.sleep("120 millis");
  return "stop" as const;
});

const program = Effect.gen(function* () {
  const fp = yield* Effect.fork(poller);
  const fc = yield* Effect.fork(condition);
  yield* Fiber.join(fc);
  yield* Fiber.interrupt(fp);
  yield* Console.log("[poller] halted by condition");
});

Effect.runPromise(program);
```

The condition fibre signals completion; the parent responds by interrupting the poller cleanly.

```ts
import { Effect, Data, Duration } from "effect";

class Cancelled extends Data.TaggedError("Cancelled")<{ readonly reason: string }> {}

const apiCall: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("200 millis");
  return "body";
});

const cancelAfter = (ms: number): Effect.Effect<never, Cancelled> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return yield* Effect.fail(new Cancelled({ reason: `deadline ${ms}ms` }));
  });

// Equivalent of: controller.abort() after 150ms.
const program: Effect.Effect<string, Cancelled> = Effect.race(apiCall, cancelAfter(150));

Effect.runPromise(Effect.either(program)).then(console.log);
```

When the cancel branch wins, `apiCall`'s fibre is interrupted — fibres are natively cancellable, no AbortController needed.

```ts
import { Effect, Fiber, Console } from "effect";

const heartbeat = Effect.forever(
  Effect.gen(function* () {
    yield* Console.log("♥");
    yield* Effect.sleep("40 millis");
  })
);

const mainTask: Effect.Effect<string> = Effect.gen(function* () {
  yield* Effect.sleep("130 millis");
  return "main done";
});

const program = Effect.gen(function* () {
  const hb = yield* Effect.fork(heartbeat);
  const result = yield* mainTask;
  yield* Fiber.interrupt(hb);
  return result;
});

Effect.runPromise(program).then(console.log);
```

The heartbeat fibre is explicitly interrupted; even if we forgot, the supervised fork would be cleaned up when the program exits.

```ts
import { Effect, Console, Duration } from "effect";

const candidate = (name: string, ms: number): Effect.Effect<string> =>
  Effect.gen(function* () {
    yield* Effect.sleep(Duration.millis(ms));
    return `${name}:${ms}`;
  }).pipe(
    Effect.onInterrupt(() => Console.log(`[interrupt] ${name}`))
  );

const program: Effect.Effect<string> = Effect.raceAll([
  candidate("A", 120),
  candidate("B", 40),
  candidate("C", 90),
]);

Effect.runPromise(program).then((r) => console.log("winner:", r));
```

`raceAll` picks B (40 ms); A and C receive an interrupt signal, and `onInterrupt` lets us observe it.

Use `Effect.tap` — it runs a side-effecting effect, ignores its result, and threads the original value through.

```ts
import { Effect, Console } from "effect";

declare const loadUser: (id: string) => Effect.Effect<{ id: string; name: string }>;

export const loadUserTraced = (id: string) =>
  loadUser(id).pipe(
    Effect.tap((u) => Console.log(`loaded user ${u.id}`)),
  );
// vs Effect.flatMap which would replace the value with the log effect's result.
```

Insert `Effect.tap` between the two steps — logging returns its own effect, but `tap` discards it and keeps the `ChargeReceipt` flowing into `persistOrder`.

```ts
import { Effect } from "effect";

interface Order { readonly id: string; readonly cents: number }
interface ChargeReceipt { readonly txId: string; readonly cents: number }
interface Persisted { readonly orderId: string; readonly txId: string }

declare const chargeCard: (o: Order) => Effect.Effect<ChargeReceipt>;
declare const persistOrder: (r: ChargeReceipt) => Effect.Effect<Persisted>;

export const placeOrder = (o: Order): Effect.Effect<Persisted> =>
  chargeCard(o).pipe(
    Effect.tap((r) => Effect.logInfo(`charged ${r.cents}c as ${r.txId}`)),
    Effect.flatMap(persistOrder),
  );
```

```ts
import { Effect, Console } from "effect";

declare const fetchJson: <T>(url: string) => Effect.Effect<T>;

export const getAndPeek = <T>(url: string): Effect.Effect<T> =>
  fetchJson<T>(url).pipe(
    Effect.tap((body) => Console.log("payload bytes:", JSON.stringify(body).length)),
  );
```

`Effect.tap` is the effectful analogue of a "passthrough log" — the return channel is still `Effect<T>`.

`Effect.tapError` taps the failure channel — if the effect succeeds, it's a no-op; if it fails, the handler runs and the original error propagates.

```ts
import { Effect, Data } from "effect";

class FetchError extends Data.TaggedError("FetchError")<{ readonly url: string; readonly cause: string }> {}

declare const fetchUrl: (url: string) => Effect.Effect<string, FetchError>;

export const fetchWithErrorLog = (url: string): Effect.Effect<string, FetchError> =>
  fetchUrl(url).pipe(
    Effect.tapError((e) => Effect.logError(`fetch ${e.url} failed: ${e.cause}`)),
  );
```

`Effect.tapBoth` takes a single `{ onSuccess, onFailure }` object, so you declare both side-effects in one place. It's equivalent to composing `tap` and `tapError`, but keeps the two handlers visually co-located — useful for matched instrumentation pairs like "request:start/request:end" metrics.

```ts
import { Effect, Data } from "effect";

class HttpError extends Data.TaggedError("HttpError")<{ readonly status: number }> {}

declare const sendRequest: (url: string) => Effect.Effect<{ status: number; body: string }, HttpError>;

export const instrumentedSend = (url: string): Effect.Effect<{ status: number; body: string }, HttpError> =>
  sendRequest(url).pipe(
    Effect.tapBoth({
      onSuccess: (res) => Effect.logInfo(`ok ${res.status} ${url}`),
      onFailure: (e) => Effect.logWarning(`fail ${e.status} ${url}`),
    }),
  );
```

```ts
import { Effect, Ref } from "effect";

interface Counters {
  readonly ok: Ref.Ref<number>;
  readonly err: Ref.Ref<number>;
}

export const withMetrics =
  <A, E, R>(counters: Counters) =>
  (eff: Effect.Effect<A, E, R>): Effect.Effect<A, E, R> =>
    eff.pipe(
      Effect.tap(() => Ref.update(counters.ok, (n) => n + 1)),
      Effect.tapError(() => Ref.update(counters.err, (n) => n + 1)),
    );

declare const fetchProfile: (id: string) => Effect.Effect<{ name: string }, Error>;

export const instrumented = (counters: Counters, id: string) =>
  fetchProfile(id).pipe(withMetrics(counters));
```

The `<A, E, R>` generics preserve the full effect signature, so `withMetrics` can wrap any effect without changing its type.

```ts
import { Effect, Clock } from "effect";

interface Row { readonly [k: string]: unknown }
declare const runSql: (sql: string) => Effect.Effect<ReadonlyArray<Row>>;
declare const recordLatency: (ms: number) => Effect.Effect<void>;

export const queryDb = (sql: string): Effect.Effect<ReadonlyArray<Row>> =>
  Effect.gen(function* () {
    const start = yield* Clock.currentTimeMillis;
    return yield* runSql(sql).pipe(
      Effect.tap(() =>
        Effect.gen(function* () {
          const end = yield* Clock.currentTimeMillis;
          yield* recordLatency(end - start);
        }),
      ),
    );
  });
```

The `tap` reads the clock again and emits the delta — the SQL result passes through untouched.

`Effect.as(log, u)` is a workaround for "run the log, keep `u`". `Effect.tap` expresses that directly.

```ts
import { Effect, Console } from "effect";

interface User { readonly id: string; readonly name: string }
declare const fetchUser: (id: string) => Effect.Effect<User>;

export const fetchUserLogged = (id: string): Effect.Effect<User> =>
  fetchUser(id).pipe(
    Effect.tap((u) => Console.log(u.name)),
