```

```ts
import { Effect, Option } from "effect";

interface Cache<A> {
  readonly get: (k: string) => Effect.Effect<Option.Option<A>>;
  readonly put: (k: string, v: A) => Effect.Effect<void>;
}

export const cachedLookup =
  <A>(cache: Cache<A>, source: (k: string) => Effect.Effect<A>) =>
  (key: string): Effect.Effect<A> =>
    Effect.gen(function* () {
      const hit = yield* cache.get(key);
      if (Option.isSome(hit)) return hit.value;
      return yield* source(key).pipe(
        Effect.tap(() => Effect.logDebug(`cache miss: ${key}`)),
        Effect.tap((v) => cache.put(key, v)),
      );
    });
```

Two taps: one for the trace log, one to populate the cache — both return the computed value unchanged.

```ts
import { Effect } from "effect";

interface Order { readonly id: string; readonly version: number }
interface Patch { readonly op: string }

declare const applyPatch: (o: Order, patch: Patch) => Effect.Effect<Order>;
declare const writeAudit: (entry: { orderId: string; op: string; version: number }) => Effect.Effect<void>;

