```ts
import { Effect, Data } from "effect";

class BadBody extends Data.TaggedError("BadBody")<{ readonly msg: string }> {}
class Unauthenticated extends Data.TaggedError("Unauthenticated")<{}> {}
class Forbidden extends Data.TaggedError("Forbidden")<{ readonly need: string }> {}
class HandlerError extends Data.TaggedError("HandlerError")<{ readonly cause: string }> {}

interface Req { readonly headers: Readonly<Record<string, string>>; readonly rawBody: string }
interface Body { readonly action: string }
interface Principal { readonly userId: string; readonly scopes: ReadonlyArray<string> }
interface Result { readonly ok: true; readonly data: unknown }
interface Res { readonly status: number; readonly body: string }

declare const parseBody: (raw: string) => Effect.Effect<Body, BadBody>;
declare const authenticate: (h: Readonly<Record<string, string>>) => Effect.Effect<Principal, Unauthenticated>;
declare const authorize: (p: Principal, action: string) => Effect.Effect<void, Forbidden>;
declare const runHandler: (p: Principal, b: Body) => Effect.Effect<Result, HandlerError>;

export const handleRequest = (
  req: Req,
): Effect.Effect<Res, BadBody | Unauthenticated | Forbidden | HandlerError> =>
  Effect.gen(function* () {
    const body = yield* parseBody(req.rawBody);
    const principal = yield* authenticate(req.headers);
    yield* authorize(principal, body.action);
    const out = yield* runHandler(principal, body);
    return { status: 200, body: JSON.stringify(out) } satisfies Res;
  });
```

```ts
import { Effect, Data, Exit } from "effect";

class BeginError extends Data.TaggedError("BeginError")<{}> {}
class CommitError extends Data.TaggedError("CommitError")<{}> {}
class RollbackError extends Data.TaggedError("RollbackError")<{}> {}

interface Tx { readonly id: string }

declare const beginTx: () => Effect.Effect<Tx, BeginError>;
declare const commitTx: (t: Tx) => Effect.Effect<void, CommitError>;
declare const rollbackTx: (t: Tx) => Effect.Effect<void, RollbackError>;

export const withTransaction =
  <A, E>(body: (tx: Tx) => Effect.Effect<A, E>): Effect.Effect<A, E | BeginError | CommitError> =>
    Effect.gen(function* () {
      const tx = yield* beginTx();
      const result = yield* Effect.exit(body(tx));
      if (Exit.isSuccess(result)) {
        yield* commitTx(tx);
        return result.value;
      }
      yield* Effect.orDie(rollbackTx(tx));
      return yield* Effect.failCause(result.cause);
    });
```

The `Exit` inspection lets us branch on success vs failure while preserving the original error in the E channel.

```ts
import { Effect, Data, Ref, Clock } from "effect";

class RefreshError extends Data.TaggedError("RefreshError")<{ readonly cause: string }> {}

interface Token { readonly value: string; readonly expiresAtMs: number }

declare const refresh: () => Effect.Effect<Token, RefreshError>;

export const makeTokenSource = (initial: Token) =>
  Effect.gen(function* () {
    const ref = yield* Ref.make<Token>(initial);
    const getValid = (): Effect.Effect<Token, RefreshError> =>
      Effect.gen(function* () {
        const now = yield* Clock.currentTimeMillis;
        const cur = yield* Ref.get(ref);
        if (cur.expiresAtMs > now + 30_000) return cur;
        const fresh = yield* refresh();
        yield* Ref.set(ref, fresh);
        return fresh;
      });
    return { getValid } as const;
  });
```

The 30-second skew prevents races where a token expires between "check" and "use".

```ts
import { Effect, Queue, Data } from "effect";

class DecodeError extends Data.TaggedError("DecodeError")<{ readonly raw: string }> {}
class DispatchError extends Data.TaggedError("DispatchError")<{ readonly topic: string }> {}

interface Envelope { readonly topic: string; readonly rawBody: string; readonly ackId: string }
interface Event { readonly topic: string; readonly payload: unknown }

declare const decode: (raw: string) => Effect.Effect<Event, DecodeError>;
declare const dispatch: (e: Event) => Effect.Effect<void, DispatchError>;
declare const ack: (id: string) => Effect.Effect<void>;

export const runSubscriber = (
  inbox: Queue.Dequeue<Envelope>,
): Effect.Effect<never, DecodeError | DispatchError> =>
  Effect.gen(function* () {
    while (true) {
      const env = yield* Queue.take(inbox);
      const event = yield* decode(env.rawBody);
      yield* dispatch(event);
      yield* ack(env.ackId);
    }
  });
```

The `while (true)` inside `Effect.gen` never resolves naturally — its return type is `Effect<never, E>`, signalling a long-running service.

```ts
import { Effect, Ref, Data } from "effect";

class CircuitOpen extends Data.TaggedError("CircuitOpen")<{ readonly failures: number }> {}

interface State { readonly failures: number; readonly openUntilMs: number }

export const makeBreaker = (threshold: number) =>
  Effect.gen(function* () {
    const state = yield* Ref.make<State>({ failures: 0, openUntilMs: 0 });
    const run = <A, E>(eff: Effect.Effect<A, E>): Effect.Effect<A, E | CircuitOpen> =>
      Effect.gen(function* () {
        const s = yield* Ref.get(state);
        if (s.failures >= threshold) {
          return yield* Effect.fail(new CircuitOpen({ failures: s.failures }));
        }
        return yield* eff.pipe(
          Effect.tap(() => Ref.set(state, { failures: 0, openUntilMs: 0 })),
          Effect.tapError(() =>
            Ref.update(state, (p) => ({ ...p, failures: p.failures + 1 })),
          ),
        );
      });
    return { run } as const;
  });
```

```ts
import { Effect, Option, Ref, HashMap } from "effect";

export const makeMemoCache = <K, V>() =>
  Effect.gen(function* () {
    const store = yield* Ref.make<HashMap.HashMap<K, V>>(HashMap.empty());
    const get = (key: K, load: (k: K) => Effect.Effect<V>): Effect.Effect<V> =>
      Effect.gen(function* () {
        const map = yield* Ref.get(store);
        const hit = HashMap.get(map, key);
        if (Option.isSome(hit)) return hit.value;
        const v = yield* load(key);
        yield* Ref.update(store, (m) => HashMap.set(m, key, v));
        return v;
      });
    return { get } as const;
