import { Effect, Queue, Ref, Data } from "effect";

class FlushError extends Data.TaggedError("FlushError")<{ readonly count: number; readonly cause: string }> {}

interface Record { readonly id: string; readonly data: unknown }

declare const bulkInsert: (rows: ReadonlyArray<Record>) => Effect.Effect<void, FlushError>;

export const runBatcher = (
  inbox: Queue.Dequeue<Record>,
  batchSize: number,
): Effect.Effect<never, FlushError> =>
  Effect.gen(function* () {
    const buf = yield* Ref.make<ReadonlyArray<Record>>([]);
    while (true) {
      const next = yield* Queue.take(inbox);
      const flushed = yield* Ref.modify(buf, (prev) => {
        const upd = [...prev, next];
        return upd.length >= batchSize ? [upd, [] as ReadonlyArray<Record>] : [[] as ReadonlyArray<Record>, upd];
      });
      if (flushed.length > 0) yield* bulkInsert(flushed);
    }
  });
```

`Ref.modify` atomically swaps the buffer so two concurrent takes can't reissue the same batch.

