  input$: Observable<string>
): Observable<Team[]> {
  return input$.pipe(
    debounceTime(300),
    map((s: string) => s.trim().toLowerCase()),
    distinctUntilChanged(),
    filter((q: string) => q.length >= 2),
    switchMap((q: string) => searchTeams$(q))
  );
}
