const withRetry = <T>(source$: Observable<T>): Observable<T> =>
  source$.pipe(
    retry({
      count: 2,
      delay: (_err, n) => timer(2 ** n * 100),
    })
  );

export function bootstrapSettings$(): Observable<SettingsBundle> {
  const theme$: Observable<Theme> = of({ mode: "dark" });
  const language$: Observable<Language> = of({ tag: "en-US" });
  const features$: Observable<ReadonlyArray<Feature>> = of([
    { name: "beta-ui", enabled: true },
  ]);

  return forkJoin({
    theme: withRetry(theme$),
    language: withRetry(language$),
    features: withRetry(features$),
  }).pipe(
    map(({ theme, language, features }): SettingsBundle => ({
      theme,
      language,
      features,
    }))
  );
}
