  // Both sources complete after one emission — forkJoin is safe.
  const user$: Observable<User> = of({ id, name: "Ada" });
  const prefs$: Observable<Prefs> = of({ theme: "dark" });

  return forkJoin({ user: user$, prefs: prefs$ }).pipe(
    map(({ user, prefs }): Bootstrap => ({
      name: user.name,
      theme: prefs.theme,
    }))
  );
}
```

