): Observable<PushAck> {
  return from(messages).pipe(
    mergeMap((m: PushMessage) => sendPush$(m), 12)
  );
}
```

Provider APNs/FCM accept parallel HTTP/2 streams, so 12 is comfortable but leaves headroom.

Without a cap, `mergeMap` subscribes to every inner observable as soon as its outer value arrives — for N outer values you get N simultaneous subscriptions. That's how you spawn 10,000 ffmpeg processes and wedge a box. Passing the concurrency argument caps the in-flight count so only N inners run; the rest queue inside the operator.

```ts
import { Observable, from } from 'rxjs';
import { mergeMap } from 'rxjs/operators';

interface TranscodeJob {
  srcUrl: string;
  targetBitrate: number;
  codec: 'h264' | 'av1';
}

interface TranscodeResult {
  srcUrl: string;
  outUrl: string;
  durationMs: number;
}

declare function transcode$(j: TranscodeJob): Observable<TranscodeResult>;

export function transcodeAll(
  jobs: ReadonlyArray<TranscodeJob>,
  cores: number
): Observable<TranscodeResult> {
  return from(jobs).pipe(
    mergeMap((j: TranscodeJob) => transcode$(j), cores)
  );
}
```

```ts
import { Observable, from } from 'rxjs';
import { mergeMap } from 'rxjs/operators';

interface ChargeIntent {
  customerId: string;
  amountCents: number;
  currency: 'usd' | 'eur';
}

interface ChargeOutcome {
  customerId: string;
  chargeId: string;
  status: 'succeeded' | 'requires_action' | 'failed';
}

declare function chargeCard$(i: ChargeIntent): Observable<ChargeOutcome>;

export function runCharges(
  intents: ReadonlyArray<ChargeIntent>
): Observable<ChargeOutcome> {
  return from(intents).pipe(
    // Payment APIs typically rate-limit hard; 4 in flight is safe.
    mergeMap((i: ChargeIntent) => chargeCard$(i), 4)
  );
}
```

`mergeMap` with cap is the right primitive: `concatMap` would be too slow for a batch, `switchMap` would cancel pending charges — catastrophic for money.

`Subject<T>` has no initial value and does not replay — a subscriber only sees values emitted AFTER it subscribes. `BehaviorSubject<T>` requires an initial value at construction, exposes `.getValue()` for synchronous reads, and immediately emits the current value to any new subscriber.

```ts
import { BehaviorSubject, Subject } from 'rxjs';

interface SessionState {
  authed: boolean;
  username: string | null;
}

const initial: SessionState = { authed: false, username: null };

// Pre-seeded + replays the latest to late subscribers.
export const session$ = new BehaviorSubject<SessionState>(initial);

// No seed, no replay — late subscribers miss prior events.
export const sessionEvents$ = new Subject<SessionState>();

session$.next({ authed: true, username: 'ada' });
const snap: SessionState = session$.getValue(); // { authed: true, ... }
void snap;
```

Reach for `BehaviorSubject` when the stream represents state; use `Subject` for one-shot events.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface FeatureFlags {
  readonly newCheckout: boolean;
  readonly betaSearch: boolean;
  readonly darkMode: boolean;
}

const initialFlags: FeatureFlags = {
  newCheckout: false,
  betaSearch: false,
  darkMode: false,
};

const _flags$ = new BehaviorSubject<FeatureFlags>(initialFlags);

export const flags$: Observable<FeatureFlags> = _flags$.asObservable();

export function updateFlags(patch: Partial<FeatureFlags>): void {
  _flags$.next({ ..._flags$.getValue(), ...patch });
}

export function currentFlags(): FeatureFlags {
  // One-shot sync read (e.g. bootstrap code). Inside streams, subscribe.
  return _flags$.getValue();
}
```

Exposing `.asObservable()` stops consumers from calling `.next` and mutating state from outside the store.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface CartItem {
  sku: string;
  quantity: number;
  priceCents: number;
}

interface Cart {
  readonly items: ReadonlyArray<CartItem>;
  readonly totalCents: number;
}

const emptyCart: Cart = { items: [], totalCents: 0 };

const _cart$ = new BehaviorSubject<Cart>(emptyCart);

export const cart$: Observable<Cart> = _cart$.asObservable();

function recompute(items: ReadonlyArray<CartItem>): Cart {
  const totalCents = items.reduce(
    (acc, i) => acc + i.priceCents * i.quantity,
    0,
  );
  return { items, totalCents };
}

export function addItem(item: CartItem): void {
  const current = _cart$.getValue();
  _cart$.next(recompute([...current.items, item]));
}

export function snapshotCart(): Cart {
  return _cart$.getValue();
}
```

Late subscribers (e.g. a header widget that mounts after items were added) see the populated cart immediately — that's the `BehaviorSubject` contract.

Three differences to internalise:

1. `BehaviorSubject<T>(initial)` requires an initial value — it is never "empty".
2. New subscribers receive the latest value synchronously on subscription.
3. `.getValue()` returns the current value without subscribing.

`Subject` has none of those — it is purely a hot event bus.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

type Theme = 'light' | 'dark' | 'system';

const _theme$ = new BehaviorSubject<Theme>('system');

export const theme$: Observable<Theme> = _theme$.asObservable();

export function setTheme(next: Theme): void {
  _theme$.next(next);
}

export function currentTheme(): Theme {
  return _theme$.getValue();
}
```

A toolbar that mounts mid-session immediately paints with the right theme — no flicker, no manual "emit the initial value" scaffolding.

Hold the `BehaviorSubject` privately and expose it via `.asObservable()`. That way callers can subscribe but cannot call `.next` to mutate.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface Counter {
  value: number;
}

const _counter$ = new BehaviorSubject<Counter>({ value: 0 });

// Public, read-only.
export const counter$: Observable<Counter> = _counter$.asObservable();

export function increment(): void {
  const current = _counter$.getValue();
  _counter$.next({ value: current.value + 1 });
}

export function snapshot(): Counter {
  return _counter$.getValue();
}
```

The `Observable<Counter>` return type is not just documentation — TypeScript will reject `counter$.next(...)` at compile time because `.next` is not in the `Observable` surface.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

type ConnectionState = 'connecting' | 'online' | 'offline';

const _connection$ = new BehaviorSubject<ConnectionState>('connecting');

export const connection$: Observable<ConnectionState> =
  _connection$.asObservable();

export function markOnline(): void {
  _connection$.next('online');
}

export function markOffline(): void {
  _connection$.next('offline');
}

export function isOnlineNow(): boolean {
  // `.getValue()` is acceptable for one-shot predicate checks.
  // Don't use it inside a pipeline — it breaks reactivity.
  return _connection$.getValue() === 'online';
}
```

Why `BehaviorSubject` not `Subject`: a React component mounting after the app already went online must paint "online" on first render. A plain `Subject` would hand back nothing until the next state change.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface State {
  count: number;
  lastAction: string;
}

type Action =
  | { type: 'inc' }
  | { type: 'dec' }
  | { type: 'reset' };

const initial: State = { count: 0, lastAction: '@@init' };

const _state$ = new BehaviorSubject<State>(initial);
export const state$: Observable<State> = _state$.asObservable();

function reduce(prev: State, action: Action): State {
  switch (action.type) {
    case 'inc':
      return { count: prev.count + 1, lastAction: 'inc' };
    case 'dec':
      return { count: prev.count - 1, lastAction: 'dec' };
    case 'reset':
      return { count: 0, lastAction: 'reset' };
  }
}

export function dispatch(action: Action): void {
  _state$.next(reduce(_state$.getValue(), action));
}

export function getState(): State {
  return _state$.getValue();
}
```

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface Preferences {
  readonly locale: string;
  readonly timeZone: string;
  readonly emailNotifications: boolean;
}

const defaults: Preferences = {
  locale: 'en-US',
  timeZone: 'UTC',
  emailNotifications: true,
};

const _prefs$ = new BehaviorSubject<Preferences>(defaults);

// Read-only stream: `.asObservable()` strips `.next` from the public type.
export const prefs$: Observable<Preferences> = _prefs$.asObservable();

export function updatePrefs(patch: Partial<Preferences>): void {
  _prefs$.next({ ..._prefs$.getValue(), ...patch });
}

