```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface AuthToken {
  readonly accessToken: string;
  readonly expiresAtMs: number;
}

const _token$ = new BehaviorSubject<AuthToken | null>(null);

export const token$: Observable<AuthToken | null> = _token$.asObservable();

export function setToken(t: AuthToken | null): void {
  _token$.next(t);
}

export function readTokenSync(): AuthToken | null {
  // Valid use of `.getValue()`: HTTP interceptor needs the token synchronously
  // before sending each request. Don't embed it inside a pipeline.
  return _token$.getValue();
}
```

The interceptor grabs the current value synchronously. A React `useAuthToken` hook can `subscribe(token$)` and receive the current value on mount. Both use cases covered by one `BehaviorSubject`.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

type Step = 0 | 1 | 2 | 3;

interface WizardState {
  readonly step: Step;
  readonly dirty: boolean;
}

const initial: WizardState = { step: 0, dirty: false };

const _wizard$ = new BehaviorSubject<WizardState>(initial);

export const wizard$: Observable<WizardState> = _wizard$.asObservable();

export function gotoStep(step: Step): void {
  _wizard$.next({ ..._wizard$.getValue(), step });
}

export function markDirty(): void {
  _wizard$.next({ ..._wizard$.getValue(), dirty: true });
}

export function snapshot(): WizardState {
  return _wizard$.getValue();
}
```

Late-mounted wizard steps see the current step immediately — `BehaviorSubject` replays the last value to new subscribers; `Subject` would not.

`.getValue()` returns the current value synchronously — no subscription, no next-tick. It is fine for one-shot reads at boundaries where you're already leaving the reactive world (form submit handler, HTTP interceptor, imperative adapter). It is NOT fine inside a pipeline — at that point you should be composing operators against the stream, not reaching for imperative state.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface Counter {
  count: number;
}

const _c$ = new BehaviorSubject<Counter>({ count: 0 });
export const counter$: Observable<Counter> = _c$.asObservable();

export function tick(): void {
  // OK: imperative tick action, not part of a stream.
  _c$.next({ count: _c$.getValue().count + 1 });
}

export function onSubmit(): number {
  // OK: leaving reactive land, grabbing the snapshot.
  return _c$.getValue().count;
}
```

