```ts
import { BehaviorSubject, Observable } from 'rxjs';

type Locale = 'en' | 'de' | 'fr' | 'ja' | 'zh';

const _locale$ = new BehaviorSubject<Locale>('en');

export const locale$: Observable<Locale> = _locale$.asObservable();

