```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface Command {
  readonly id: string;
  readonly description: string;
}

interface UndoState {
  readonly past: ReadonlyArray<Command>;
  readonly future: ReadonlyArray<Command>;
}

const initial: UndoState = { past: [], future: [] };

const _undo$ = new BehaviorSubject<UndoState>(initial);

export const undo$: Observable<UndoState> = _undo$.asObservable();

export function doCommand(c: Command): void {
  const s = _undo$.getValue();
  _undo$.next({ past: [...s.past, c], future: [] });
}

export function undoOne(): void {
  const s = _undo$.getValue();
  if (s.past.length === 0) {
    return;
  }
  const last = s.past[s.past.length - 1] as Command;
  _undo$.next({
    past: s.past.slice(0, -1),
    future: [last, ...s.future],
  });
}

export function undoSnapshot(): UndoState {
  return _undo$.getValue();
}
```

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface User {
  id: string;
  email: string;
  displayName: string;
}

class CurrentUserService {
  private readonly _user$ = new BehaviorSubject<User | null>(null);

  readonly user$: Observable<User | null> = this._user$.asObservable();

  setUser(u: User | null): void {
    this._user$.next(u);
  }

  // Sync read — valid at imperative boundaries only.
  getUserSnapshot(): User | null {
    return this._user$.getValue();
  }
}

export const currentUserService = new CurrentUserService();
```

Injecting the service gives consumers both the subscribable `user$` stream and the synchronous `getUserSnapshot()` — no duplicated state, one source of truth.

Both replay the last value to late subscribers, but `BehaviorSubject<T>(initial)` REQUIRES an initial value — meaning every subscriber, including the very first one, sees a valid `T`. With `ReplaySubject<T>(1)` there is no initial; a subscriber that beats the first `.next()` gets nothing until one arrives. `BehaviorSubject` also exposes `.getValue()` for synchronous reads, which `ReplaySubject` does not.

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface AppConfig {
  readonly apiUrl: string;
  readonly featureX: boolean;
}

const defaults: AppConfig = { apiUrl: '/api', featureX: false };

const _config$ = new BehaviorSubject<AppConfig>(defaults);

export const config$: Observable<AppConfig> = _config$.asObservable();

export function updateConfig(patch: Partial<AppConfig>): void {
  _config$.next({ ..._config$.getValue(), ...patch });
}

export function configSnapshot(): AppConfig {
  return _config$.getValue();
}
```

```ts
import { BehaviorSubject, Observable } from 'rxjs';

interface LayoutState {
  readonly sidebarOpen: boolean;
  readonly rightPanelOpen: boolean;
  readonly zoom: number;
}

const defaults: LayoutState = {
  sidebarOpen: true,
  rightPanelOpen: false,
  zoom: 1,
};

const _layout$ = new BehaviorSubject<LayoutState>(defaults);

export const layout$: Observable<LayoutState> = _layout$.asObservable();

export function toggleSidebar(): void {
  const s = _layout$.getValue();
  _layout$.next({ ...s, sidebarOpen: !s.sidebarOpen });
}

export function setZoom(zoom: number): void {
  _layout$.next({ ..._layout$.getValue(), zoom });
}

export function layoutSnapshot(): LayoutState {
  return _layout$.getValue();
}
```

A freshly mounted layout component sees the current state on first render — no flicker, no manual "send me the initial value" dance.

A `ReplaySubject<T>(n)` buffers the last `n` emissions and replays them to every new subscriber. Contrast with `BehaviorSubject` which replays only the latest value.

```ts
import { ReplaySubject, Observable } from 'rxjs';

interface DomainEvent {
  readonly type: string;
  readonly at: number;
  readonly payload: unknown;
}

// Buffer the last 5 events for late subscribers.
const bus$: ReplaySubject<DomainEvent> = new ReplaySubject<DomainEvent>(5);

// Emit before anyone subscribes.
bus$.next({ type: 'app.boot', at: Date.now(), payload: null });
bus$.next({ type: 'user.login', at: Date.now(), payload: { id: 'u-1' } });
bus$.next({ type: 'cart.add', at: Date.now(), payload: { sku: 'x' } });

// Expose read-only view.
export const events$: Observable<DomainEvent> = bus$.asObservable();

// A subscriber attaching NOW still receives the 3 buffered events.
events$.subscribe((e: DomainEvent) => console.log('replay:', e.type));

export function publish(evt: DomainEvent): void {
  bus$.next(evt);
}
```

Use `new ReplaySubject<T>(bufferSize)` with `bufferSize: 2`. Unlike `BehaviorSubject` which holds just the latest, `ReplaySubject(2)` keeps a sliding window of the two most recent emissions.

```ts
import { ReplaySubject } from 'rxjs';

const ticker$: ReplaySubject<number> = new ReplaySubject<number>(2);

ticker$.next(1);
ticker$.next(2);
ticker$.next(3);

// Late subscriber gets [2, 3] — the last 2 values — then any future emissions.
ticker$.subscribe((v: number) => console.log('got', v));

ticker$.next(4); // also delivered live
```

```ts
import { ReplaySubject, Observable } from 'rxjs';

type LogLevel = 'debug' | 'info' | 'warn' | 'error';

interface LogLine {
  readonly level: LogLevel;
  readonly message: string;
  readonly at: number;
}

// Keep a rolling 50-line buffer for late subscribers (e.g. DevTools panels).
const sink$: ReplaySubject<LogLine> = new ReplaySubject<LogLine>(50);

export function log(level: LogLevel, message: string): void {
  sink$.next({ level, message, at: Date.now() });
}

// Read-only public view. A BehaviorSubject would only replay the latest line.
export const logs$: Observable<LogLine> = sink$.asObservable();

// Example: some lines emitted before any panel is open.
log('info', 'boot');
log('debug', 'config loaded');

// Later: DevTools attaches and receives buffered history immediately.
logs$.subscribe((line: LogLine) => console.log(`[${line.level}]`, line.message));
```

`ReplaySubject<T>(bufferSize)` stores the last `bufferSize` values it has emitted. Every new subscriber receives that buffered history immediately on subscribe, then live emissions thereafter. With no argument it replays ALL historical values — use a number unless you really want unbounded memory.

