Pass `windowTime` as the second constructor argument. Values older than 10_000 ms are dropped from the buffer before replay.

```ts
import { ReplaySubject, Observable } from 'rxjs';

// bufferSize=100, windowTime=10_000 ms. Entries are evicted if EITHER limit
// is exceeded — whichever happens first.
const sink$: ReplaySubject<string> = new ReplaySubject<string>(100, 10_000);

export function emit(s: string): void {
  sink$.next(s);
