```ts
import { Observable, OperatorFunction } from 'rxjs';
import { tap } from 'rxjs/operators';

export function logTap<T>(label: string): OperatorFunction<T, T> {
  return (source$: Observable<T>): Observable<T> =>
    source$.pipe(
      tap({
        next: (v: T) => console.log(`[${label}] next`, v),
        error: (e: unknown) => console.error(`[${label}] error`, e),
        complete: () => console.log(`[${label}] complete`),
      })
    );
}

// Usage:
// of(1, 2, 3).pipe(logTap<number>('nums'), map(x => x * 2)).subscribe();
```

Because `OperatorFunction<T, T>` preserves the element type, this composes without type annotations at call sites.

`map` returns a new observable of the transformed values; `tap` returns the *same* observable and exists purely for side effects. A misused `tap` can't corrupt the stream — that's the point.

