```ts
import { MonoTypeOperatorFunction, Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface BackoffPolicy {
  readonly count: number;
  readonly baseMs: number;
  readonly capMs: number;
}

const DEFAULT_POLICY: BackoffPolicy = { count: 5, baseMs: 300, capMs: 10_000 };

export function withBackoff<T>(
  policy: BackoffPolicy = DEFAULT_POLICY
): MonoTypeOperatorFunction<T> {
  return (src$: Observable<T>): Observable<T> =>
    src$.pipe(
      retry({
        count: policy.count,
        delay: (_err: unknown, attempt: number): Observable<number> =>
          timer(Math.min(2 ** attempt * policy.baseMs, policy.capMs)),
      })
    );
}

declare const source$: Observable<string>;
export const reliable$: Observable<string> = source$.pipe(withBackoff<string>());
```

The `BackoffPolicy` type is a ReadOnly record so callers can't mutate it after passing it in.

A thundering herd is many clients retrying in lockstep after a shared failure — they hit the recovering server simultaneously and knock it over again. Exponential backoff (plus jitter) decorrelates retry attempts across clients so the load spreads out.

```ts
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface Task {
  id: string;
}

interface TaskResult {
  id: string;
  ok: boolean;
}

declare function runTask$(t: Task): Observable<TaskResult>;

export function runTaskResilient$(t: Task): Observable<TaskResult> {
  return runTask$(t).pipe(
    retry({
      count: 6,
      delay: (_err: unknown, attempt: number): Observable<number> => {
        const ceiling: number = Math.min(2 ** attempt * 200, 15_000);
        const jittered: number = Math.floor(Math.random() * ceiling);
        return timer(jittered);
      },
    })
  );
}
```

Full jitter (random between 0 and the exponential ceiling) is AWS's recommended pattern — the `Math.random()` call spreads the retries.

```ts
import { Observable, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface S3Put {
  bucket: string;
  key: string;
  body: Uint8Array;
}

interface PutResult {
  etag: string;
}

declare function putObject$(p: S3Put): Observable<PutResult>;

const BUDGET_MS = 20_000;

export function uploadResilient$(p: S3Put): Observable<PutResult> {
  let elapsed = 0;
  return putObject$(p).pipe(
    retry({
      count: Infinity,
      delay: (err: unknown, attempt: number): Observable<number> => {
        const wait: number = 2 ** attempt * 250;
        if (elapsed + wait > BUDGET_MS) {
          return throwError(() => err) as unknown as Observable<number>;
        }
        elapsed += wait;
        return timer(wait);
      },
    })
  );
}
```

The closure-tracked `elapsed` counter enforces a total budget even though `count` is infinite — once the cumulative wait would exceed 20 s, the error propagates.

